export const MOCK_BROADCASTS: Broadcast[] = [
  {
    id: '1',
    title: 'Cholera Prevention',
    content: 'Ensure all water is boiled before drinking due to local outbreak concerns.',
    date: '2023-10-25',
    priority: 'high'
  },
  {
    id: '2',
    title: 'Vaccination Schedule',
