          {showCamera && (
            <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-4">
              <video ref={videoRef} autoPlay playsInline className="w-full max-w-sm h-3/4 object-cover rounded-[40px]" />
              <div className="flex gap-8 mt-10">
                <button onClick={closeCamera} className="w-16 h-16 bg-white/20 rounded-full text-white text-xl">✕</button>
                <button onClick={capturePhoto} className="w-20 h-20 bg-white rounded-full border-4 border-gray-300 shadow-2xl active:scale-90 transition-all"></button>
              </div>
              <canvas ref={canvasRef} className="hidden" />
            </div>
          )}
        </div>
      )}

      {activeTab === 'directory' && (
        <div className="space-y-4 animate-fadeIn">
          <div className="flex gap-2 overflow-x-auto pb-4 scrollbar-hide">
            {['All', 'Clinic', 'Hospital', 'Pharmacy', 'Volunteer'].map(cat => (
              <button key={cat} className="px-5 py-2.5 bg-gray-100 rounded-full text-xs font-black text-gray-500 active:bg-red-600 active:text-white whitespace-nowrap">{cat}</button>
            ))}
          </div>
          <div className="space-y-4">
            {dynamicDirectory.map((place, i) => (
              <div key={i} className="bg-white p-5 rounded-[32px] border border-gray-50 shadow-sm flex items-start gap-5">
                <div className="w-14 h-14 bg-red-50 text-red-600 rounded-2xl flex items-center justify-center text-3xl">🏥</div>
                <div className="flex-1">
                  <h4 className="font-black text-gray-800">{place.name}</h4>
                  <p className="text-[10px] font-bold text-red-600 uppercase mb-2">{place.type} • {place.distance}</p>
                  <div className="flex gap-2">
                    <a href={`tel:${place.phone}`} className="px-5 py-2 bg-red-600 text-white text-[10px] font-black rounded-xl shadow-md">CALL NOW</a>
                    <button className="px-5 py-2 bg-gray-50 text-gray-500 text-[10px] font-black rounded-xl">LOCATION</button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'profile' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="text-center p-10 bg-gray-50 rounded-[48px]">
            <div className="w-24 h-24 bg-red-600 text-white text-5xl font-black flex items-center justify-center rounded-full mx-auto mb-6 shadow-2xl border-4 border-white">
              {currentUser.fullName.charAt(0)}
            </div>
            <h2 className="text-2xl font-black text-gray-800">{currentUser.fullName}</h2>
            <p className="text-gray-400 text-xs font-bold uppercase mt-1 tracking-widest">{currentUser.role}</p>
          </div>
          <div className="bg-white p-8 rounded-[40px] border-2 border-gray-50 shadow-sm space-y-6">
            <InfoRow label="Email" value={currentUser.email} />
            <InfoRow label="Phone" value={currentUser.phone} />
            <InfoRow label="Location" value={currentUser.address} />
            {currentUser.role === UserRole.PATIENT && (
              <div className="grid grid-cols-2 gap-4 pt-4 border-t border-gray-100">
                <InfoBox label="Blood" value={currentUser.bloodGroup || 'N/A'} />
                <InfoBox label="Genotype" value={currentUser.genotype || 'N/A'} />
              </div>
            )}
            {currentUser.showInHelp && (
              <div className="bg-green-50 p-4 rounded-2xl text-center border border-green-100">
                <p className="text-[10px] font-black text-green-700 uppercase">Status: Helping Community</p>
              </div>
            )}
          </div>
          <button onClick={handleLogout} className="w-full py-5 bg-gray-100 text-gray-400 rounded-3xl font-black uppercase text-xs tracking-widest">Sign Out</button>
        </div>
      )}
    </Layout>
  );
};

const QuickAction: React.FC<{ icon: string; label: string; bg: string; color: string; onClick: () => void }> = ({ icon, label, bg, color, onClick }) => (
  <button onClick={onClick} className={`${bg} p-8 rounded-[40px] border border-transparent hover:border-current flex flex-col items-center shadow-sm active:scale-95 transition-all`}>
    <span className="text-4xl mb-3">{icon}</span>
    <span className={`font-black uppercase text-[10px] tracking-widest ${color}`}>{label}</span>
  </button>
);

const InfoRow: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="flex flex-col">
    <span className="text-[8px] font-black text-gray-300 uppercase tracking-widest mb-1">{label}</span>
    <span className="text-sm font-bold text-gray-700">{value}</span>
  </div>
);

const InfoBox: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="bg-gray-50 p-4 rounded-2xl text-center">
    <span className="text-[8px] font-black text-gray-300 uppercase tracking-widest mb-1 block">{label}</span>
    <span className="text-lg font-black text-gray-800">{value}</span>
  </div>
);

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, UserRole, Language, EmergencyGuide, InteractiveStep, HealthFacility } from './types';
import { EMERGENCY_GUIDES, HEALTH_DIRECTORY, MOCK_BROADCASTS } from './constants';
import Layout from './components/Layout';
import SOSButton from './components/SOSButton';
import AuthScreen from './views/AuthScreen';
import { GeminiService } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [activeTab, setActiveTab] = useState('home');
  const [selectedGuide, setSelectedGuide] = useState<EmergencyGuide | null>(null);
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [showFeedback, setShowFeedback] = useState(false);
  const [symptomText, setSymptomText] = useState('');
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [checkerResult, setCheckerResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [showCamera, setShowCamera] = useState(false);

  // Directory specific state
  const [directoryCategory, setDirectoryCategory] = useState('All');

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('user_profile');
    if (saved) setCurrentUser(JSON.parse(saved));
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('user_profile');
    setCurrentUser(null);
  };

  const dynamicDirectory = useMemo(() => {
    const allRegistered = JSON.parse(localStorage.getItem('all_registered_users') || '[]');
    const helpers: HealthFacility[] = allRegistered
      .filter((u: UserProfile) => u.showInHelp && u.id !== currentUser?.id)
      .map((u: UserProfile) => ({
        name: u.role === UserRole.ORGANIZATION ? (u.organizationName || 'Unnamed Org') : u.fullName,
        type: u.role === UserRole.ORGANIZATION ? (u.firmType === 'Others' ? (u.otherFirmType as any || 'Organization') : u.firmType) : 'Volunteer',
        distance: 'Local Helper',
        phone: u.phone,
        address: u.address
      }));

    return [...HEALTH_DIRECTORY, ...helpers];
  }, [currentUser]);

  const filteredDirectory = useMemo(() => {
    if (directoryCategory === 'All') return dynamicDirectory;
    return dynamicDirectory.filter(item => {
      const type = item.type.toLowerCase();
      const cat = directoryCategory.toLowerCase();

      // Handle the 'Volunteers' vs 'Volunteer' or 'Caregiver' mapping
      if (cat === 'volunteers') {
        return type === 'volunteer' || type === 'caregiver';
      }

      return type.includes(cat.slice(0, -1)) || type.includes(cat);
    });
  }, [dynamicDirectory, directoryCategory]);

  const handleGetDirections = (address: string) => {
    if (!address) {
      alert("Address not available for this facility.");
      return;
    }
    const encodedAddress = encodeURIComponent(address);
    // Standard Google Maps Directions URL
    const mapUrl = `https://www.google.com/maps/dir/?api=1&destination=${encodedAddress}`;
    window.open(mapUrl, '_blank');
  };

  const startVoiceInput = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Voice input not supported.");
      return;
    }
    const recognition = new SpeechRecognition();
    recognition.lang = currentUser?.preferredLanguage || 'en-US';
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = (e: any) => setSymptomText(prev => prev + ' ' + e.results[0][0].transcript);
    recognition.start();
  };

  const openCamera = async () => {
    setShowCamera(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) videoRef.current.srcObject = stream;
    } catch {
      alert("Camera error.");
      setShowCamera(false);
    }
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      canvasRef.current.width = videoRef.current.videoWidth;
      canvasRef.current.height = videoRef.current.videoHeight;
      ctx?.drawImage(videoRef.current, 0, 0);
      setCapturedImage(canvasRef.current.toDataURL('image/jpeg'));
      closeCamera();
    }
  };

  const closeCamera = () => {
    if (videoRef.current?.srcObject) (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
    setShowCamera(false);
  };

  const checkSymptoms = async () => {
    if (!symptomText && !capturedImage) return;
    setLoading(true);
    try {
      const result = await GeminiService.checkSymptoms(symptomText || "Image provided.", capturedImage || undefined);
      setCheckerResult(result);
    } catch {
      alert("AI analysis failed.");
    } finally {
      setLoading(false);
    }
  };

  const speakGuide = (guide: EmergencyGuide, step?: InteractiveStep) => {
    const text = step ? step.text : guide.title;
    GeminiService.speakText(text);
  };

  const handleNextStep = () => {
    if (selectedGuide && currentStepIndex < selectedGuide.steps.length - 1) {
      setShowFeedback(true);
      setTimeout(() => {
        setCurrentStepIndex(currentStepIndex + 1);
        setShowFeedback(false);
        speakGuide(selectedGuide, selectedGuide.steps[currentStepIndex + 1]);
      }, 1200);
    } else {
      setCurrentStepIndex(selectedGuide?.steps.length || 0);
    }
  };

  if (!currentUser) {
    return <AuthScreen onLogin={(user) => { setCurrentUser(user); localStorage.setItem('user_profile', JSON.stringify(user)); }} />;
  }

  return (
    <Layout 
      title={activeTab === 'guides' && selectedGuide ? selectedGuide.title : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} 
      activeTab={activeTab} 
      setActiveTab={(tab) => { setActiveTab(tab); setSelectedGuide(null); setCurrentStepIndex(0); }}
      onBack={selectedGuide ? () => currentStepIndex > 0 ? setCurrentStepIndex(prev => prev - 1) : setSelectedGuide(null) : undefined}
    >
      {activeTab === 'home' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-black text-gray-800">Hi, {currentUser.fullName.split(' ')[0]}</h2>
              <p className="text-gray-400 text-sm font-medium">Ready to help you stay safe.</p>
            </div>
            <button onClick={() => setActiveTab('profile')} className="w-12 h-12 bg-red-600 rounded-full flex items-center justify-center text-white text-xl font-black shadow-lg">
              {currentUser.fullName.charAt(0)}
            </button>
          </div>
          <SOSButton />
          <div className="grid grid-cols-2 gap-4">
            <QuickAction icon="🩹" label="First Aid" bg="bg-blue-50" color="text-blue-900" onClick={() => setActiveTab('guides')} />
            <QuickAction icon="🩺" label="Check Help" bg="bg-purple-50" color="text-purple-900" onClick={() => setActiveTab('checker')} />
          </div>
          <section>
            <h3 className="font-bold text-lg mb-3">📢 Alerts</h3>
            <div className="space-y-3">
              {MOCK_BROADCASTS.map(alert => (
                <div key={alert.id} className={`p-4 rounded-3xl border ${alert.priority === 'high' ? 'bg-orange-50 border-orange-200' : 'bg-gray-50 border-gray-100'}`}>
                  <h4 className="font-bold text-sm text-gray-700">{alert.title}</h4>
                  <p className="text-gray-500 text-xs mt-1">{alert.content}</p>
                </div>
              ))}
            </div>
          </section>
        </div>
      )}

      {activeTab === 'guides' && (
        <div className="animate-fadeIn">
          {!selectedGuide ? (
            <div className="grid grid-cols-2 gap-4">
              {EMERGENCY_GUIDES.map(guide => (
                <button key={guide.id} onClick={() => { setSelectedGuide(guide); speakGuide(guide, guide.steps[0]); }} className="bg-white p-6 rounded-[32px] border-2 border-gray-50 shadow-sm flex flex-col items-center hover:border-red-200 transition-all active:scale-95">
                  <span className="text-4xl mb-3">{guide.icon}</span>
                  <span className="font-bold text-gray-800 text-sm text-center">{guide.title}</span>
                </button>
              ))}
            </div>
          ) : currentStepIndex < selectedGuide.steps.length ? (
            <div className="space-y-6">
              <div className="relative overflow-hidden rounded-[32px] shadow-xl">
                <img src={selectedGuide.image} className="w-full h-52 object-cover" alt={selectedGuide.title} />
                <div className="absolute bottom-4 left-4 bg-red-600 text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-wider">
                  Step {currentStepIndex + 1}
                </div>
              </div>
              <div className="flex items-center justify-between">
                <h2 className="text-2xl font-black text-gray-900 leading-tight flex-1 mr-4">{selectedGuide.steps[currentStepIndex].text}</h2>
                <button onClick={() => speakGuide(selectedGuide, selectedGuide.steps[currentStepIndex])} className="p-3 bg-red-50 text-red-600 rounded-2xl">🔊</button>
              </div>
              {showFeedback ? (
                <div className="bg-green-50 p-6 rounded-[32px] border-2 border-green-200 text-center animate-bounce">
                  <p className="text-green-800 font-black">{selectedGuide.steps[currentStepIndex].feedback}</p>
                </div>
              ) : (
                <button onClick={handleNextStep} className="w-full py-6 bg-red-600 text-white rounded-[32px] font-black text-xl shadow-xl active:scale-95 transition-all uppercase">Done</button>
              )}
            </div>
          ) : (
            <div className="bg-blue-50 p-10 rounded-[48px] text-center border-2 border-blue-100">
              <span className="text-6xl block mb-6">✅</span>
              <h2 className="text-3xl font-black text-blue-900 mb-4">You're Safe</h2>
              <p className="text-blue-800 font-medium mb-8">{selectedGuide.furtherHelp}</p>
              <button onClick={() => { setSelectedGuide(null); setActiveTab('home'); }} className="w-full py-4 bg-blue-900 text-white rounded-2xl font-bold">RETURN HOME</button>
            </div>
          )}
        </div>
      )}

      {activeTab === 'checker' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-[40px] border-2 border-gray-50 shadow-xl space-y-4">
            <h3 className="text-xl font-black text-gray-800">Smart Symptom Checker</h3>
            <textarea 
              value={symptomText} 
              onChange={(e) => setSymptomText(e.target.value)} 
              placeholder="Describe symptoms here or use voice..." 
              className="w-full h-32 p-5 bg-gray-50 rounded-3xl border-0 focus:ring-2 focus:ring-red-500 outline-none text-sm resize-none"
            />
            <div className="flex gap-4">
              <button onClick={startVoiceInput} className={`flex-1 py-4 rounded-2xl font-bold flex items-center justify-center gap-2 ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-100 text-gray-600'}`}>🎤 Voice</button>
              <button onClick={openCamera} className="flex-1 py-4 bg-gray-100 text-gray-600 rounded-2xl font-bold flex items-center justify-center gap-2">📷 Camera</button>
            </div>
            {capturedImage && (
              <div className="relative rounded-2xl overflow-hidden border-2 border-gray-100 h-40">
                <img src={capturedImage} className="w-full h-full object-cover" />
                <button onClick={() => setCapturedImage(null)} className="absolute top-2 right-2 bg-red-600 text-white w-8 h-8 rounded-full">✕</button>
              </div>
            )}
            <button onClick={checkSymptoms} disabled={loading} className="w-full py-5 bg-red-600 text-white rounded-2xl font-black shadow-lg disabled:opacity-50">
              {loading ? 'Analyzing...' : 'Analyze Symptoms'}
            </button>
          </div>
          {checkerResult && (
            <div className="bg-white p-8 rounded-[40px] shadow-2xl animate-slideUp border border-gray-50">
              <div className="flex justify-between items-start mb-4">
                <span className={`px-4 py-1 rounded-full text-[10px] font-black uppercase ${checkerResult.severity === 'High' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600'}`}>
                  {checkerResult.severity} Risk
                </span>
                <button onClick={() => setCheckerResult(null)} className="text-gray-300">✕</button>
              </div>
              <p className="text-gray-600 font-medium italic mb-6 leading-relaxed">"{checkerResult.advice}"</p>
              <div className="space-y-3">
                {checkerResult.steps.map((s: string, i: number) => (
                  <div key={i} className="flex gap-3 text-sm text-gray-700 bg-gray-50 p-4 rounded-2xl font-medium">
                    <span className="text-red-500 font-black">{i+1}.</span>
                    <span>{s}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
          {showCamera && (
            <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-4">
              <video ref={videoRef} autoPlay playsInline className="w-full max-sm:max-w-xs h-3/4 object-cover rounded-[40px]" />
              <div className="flex gap-8 mt-10">
                <button onClick={closeCamera} className="w-16 h-16 bg-white/20 rounded-full text-white text-xl">✕</button>
                <button onClick={capturePhoto} className="w-20 h-20 bg-white rounded-full border-4 border-gray-300 shadow-2xl active:scale-90 transition-all"></button>
              </div>
              <canvas ref={canvasRef} className="hidden" />
            </div>
          )}
        </div>
      )}

      {activeTab === 'directory' && (
        <div className="space-y-4 animate-fadeIn">
          <div className="flex gap-2 overflow-x-auto pb-4 scrollbar-hide px-1">
            {['All', 'Clinic', 'Hospital', 'Pharmacy', 'Volunteers'].map(cat => (
              <button 
                key={cat} 
                onClick={() => setDirectoryCategory(cat)}
                className={`px-5 py-2.5 rounded-full text-xs font-black whitespace-nowrap transition-all duration-300 shadow-sm border ${
                  directoryCategory === cat 
                    ? 'bg-red-600 text-white border-red-700 scale-105' 
                    : 'bg-white text-gray-500 border-gray-100'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>

          <div className="space-y-4">
            {filteredDirectory.length > 0 ? (
              filteredDirectory.map((place, i) => (
                <div key={i} className="bg-white p-5 rounded-[32px] border border-gray-50 shadow-sm flex items-start gap-5 hover:shadow-md transition-shadow">
                  <div className="w-14 h-14 bg-red-50 text-red-600 rounded-2xl flex items-center justify-center text-3xl flex-shrink-0">
                    {place.type.toLowerCase().includes('pharmacy') ? '💊' : 
                     place.type.toLowerCase().includes('volunteer') || place.type.toLowerCase().includes('caregiver') ? '🤝' : '🏥'}
                  </div>
                  <div className="flex-1 min-w-0">
                    <h4 className="font-black text-gray-800 truncate">{place.name}</h4>
                    <p className="text-[10px] font-bold text-red-600 uppercase mb-2 truncate">
                      {place.type} • {place.distance}
                    </p>
                    <div className="flex gap-2">
                      <a 
                        href={`tel:${place.phone}`} 
                        className="flex-1 px-4 py-2 bg-red-600 text-white text-[10px] font-black rounded-xl shadow-md text-center active:scale-95 transition-all"
                      >
                        CALL NOW
                      </a>
                      <button 
                        onClick={() => handleGetDirections(place.address)}
                        className="flex-1 px-4 py-2 bg-gray-50 text-gray-500 text-[10px] font-black rounded-xl active:scale-95 transition-all hover:bg-gray-100"
                      >
                        LOCATION
                      </button>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center py-20 bg-gray-50 rounded-[40px] border-2 border-dashed border-gray-200">
                <span className="text-4xl block mb-2">🔍</span>
                <p className="text-gray-400 font-bold">No {directoryCategory.toLowerCase()} found</p>
              </div>
            )}
          </div>
        </div>
      )}

      {activeTab === 'profile' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="text-center p-10 bg-gray-50 rounded-[48px]">
            <div className="w-24 h-24 bg-red-600 text-white text-5xl font-black flex items-center justify-center rounded-full mx-auto mb-6 shadow-2xl border-4 border-white">
              {currentUser.fullName.charAt(0)}
            </div>
            <h2 className="text-2xl font-black text-gray-800">{currentUser.fullName}</h2>
            <p className="text-gray-400 text-xs font-bold uppercase mt-1 tracking-widest">{currentUser.role}</p>
          </div>
          <div className="bg-white p-8 rounded-[40px] border-2 border-gray-50 shadow-sm space-y-6">
            <InfoRow label="Email" value={currentUser.email} />
            <InfoRow label="Phone" value={currentUser.phone} />
            <InfoRow label="Location" value={currentUser.address} />
            {currentUser.role === UserRole.PATIENT && (
              <div className="grid grid-cols-2 gap-4 pt-4 border-t border-gray-100">
                <InfoBox label="Blood" value={currentUser.bloodGroup || 'N/A'} />
                <InfoBox label="Genotype" value={currentUser.genotype || 'N/A'} />
              </div>
            )}
            {currentUser.showInHelp && (
              <div className="bg-green-50 p-4 rounded-2xl text-center border border-green-100">
                <p className="text-[10px] font-black text-green-700 uppercase">Status: Helping Community</p>
              </div>
            )}
          </div>
          <button onClick={handleLogout} className="w-full py-5 bg-gray-100 text-gray-400 rounded-3xl font-black uppercase text-xs tracking-widest">Sign Out</button>
        </div>
      )}
    </Layout>
  );
};

const QuickAction: React.FC<{ icon: string; label: string; bg: string; color: string; onClick: () => void }> = ({ icon, label, bg, color, onClick }) => (
  <button onClick={onClick} className={`${bg} p-8 rounded-[40px] border border-transparent hover:border-current flex flex-col items-center shadow-sm active:scale-95 transition-all`}>
    <span className="text-4xl mb-3">{icon}</span>
    <span className={`font-black uppercase text-[10px] tracking-widest ${color}`}>{label}</span>
  </button>
);

const InfoRow: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="flex flex-col">
    <span className="text-[8px] font-black text-gray-300 uppercase tracking-widest mb-1">{label}</span>
    <span className="text-sm font-bold text-gray-700">{value}</span>
  </div>
);

const InfoBox: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="bg-gray-50 p-4 rounded-2xl text-center">
    <span className="text-[8px] font-black text-gray-300 uppercase tracking-widest mb-1 block">{label}</span>
    <span className="text-lg font-black text-gray-800">{value}</span>
  </div>
);

export default App;

