import React, { useState } from 'react';
import { UserProfile, EmergencyContact } from '../types';

interface SOSButtonProps {
  user: UserProfile;
  onUpdateContacts: (contacts: EmergencyContact[]) => void;
}

const SOSButton: React.FC<SOSButtonProps> = ({ user, onUpdateContacts }) => {
  const [isActive, setIsActive] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [countdown, setCountdown] = useState(5);

  const handleSOS = () => {
    if (user.sosContacts.length === 0) {
      alert("Please add at least one emergency contact in SOS Settings first.");
      setShowSettings(true);
      return;
    }
    setIsActive(true);
    let count = 5;
    const interval = setInterval(() => {
      count--;
      setCountdown(count);
      if (count === 0) {
        clearInterval(interval);
        triggerAlert();
      }
    }, 1000);
  };

  const triggerAlert = () => {
    const contactNames = user.sosContacts.map(c => c.name).join(", ");
    alert(`🚨 ALERT BROADCASTED!\n\nSending GPS and Medical Profile to:\n${contactNames}\n\nLocal authorities have been notified.`);
    setIsActive(false);
    setCountdown(5);
  };

  const addContact = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newContact: EmergencyContact = {
      id: Math.random().toString(36).substr(2, 9),
      name: formData.get('name') as string,
      phone: formData.get('phone') as string,
      type: formData.get('type') as any,
    };

    if (user.sosContacts.length >= 5) {
      alert("Maximum 5 contacts allowed (2 Family, 2 Org, 1 National).");
      return;
    }

    onUpdateContacts([...user.sosContacts, newContact]);
    e.currentTarget.reset();
  };

  const removeContact = (id: string) => {
    onUpdateContacts(user.sosContacts.filter(c => c.id !== id));
  };

  return (
    <>
      <div className="bg-red-50 p-6 rounded-[40px] shadow-sm border border-red-100 flex flex-col items-center relative overflow-hidden">
        <button 
          onClick={() => setShowSettings(true)}
          className="absolute top-4 right-4 p-2 bg-white rounded-full shadow-sm text-gray-400 hover:text-red-600 transition-colors"
        >
          ⚙️
        </button>
        <button 
          onClick={handleSOS}
          className="w-32 h-32 rounded-full bg-red-600 shadow-[0_0_30px_rgba(220,38,38,0.5)] flex items-center justify-center animate-pulse active:scale-90 transition-transform relative z-10"
        >
          <span className="text-white text-4xl font-black italic tracking-tighter">SOS</span>
        </button>
        <p className="mt-4 text-red-800 font-black text-lg">EMERGENCY HELP</p>
        <p className="text-red-600 text-[10px] font-bold uppercase tracking-widest opacity-60">
          {user.sosContacts.length} contacts configured
        </p>
      </div>

      {showSettings && (
        <div className="fixed inset-0 z-[110] bg-black/60 backdrop-blur-sm flex items-end justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[40px] p-8 animate-slideUp max-h-[80vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-black text-gray-800">SOS Network</h3>
              <button onClick={() => setShowSettings(false)} className="text-gray-400 text-2xl">✕</button>
            </div>

            <div className="space-y-4 mb-8">
              {user.sosContacts.map(contact => (
                <div key={contact.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl border border-gray-100">
                  <div>
                    <p className="font-black text-gray-800 text-sm">{contact.name}</p>
                    <p className="text-[10px] text-red-600 font-bold uppercase">{contact.type} • {contact.phone}</p>
                  </div>
                  <button onClick={() => removeContact(contact.id)} className="text-red-300 hover:text-red-600">🗑️</button>
                </div>
              ))}
              {user.sosContacts.length === 0 && (
                <p className="text-center py-4 text-gray-400 text-xs italic">Your emergency list is empty.</p>
              )}
            </div>

            <form onSubmit={addContact} className="space-y-3 bg-red-50 p-6 rounded-3xl">
              <p className="text-[10px] font-black text-red-800 uppercase tracking-widest mb-2">Add Contact</p>
              <input name="name" placeholder="Full Name" className="w-full p-3 rounded-xl border-none text-sm" required />
              <input name="phone" placeholder="Phone Number" className="w-full p-3 rounded-xl border-none text-sm" required />
              <select name="type" className="w-full p-3 rounded-xl border-none text-sm bg-white">
                <option value="Family">Family Member</option>
                <option value="Org">Organization/Volunteer</option>
                <option value="National">National Emergency</option>
              </select>
              <button type="submit" className="w-full py-3 bg-red-600 text-white rounded-xl font-black text-xs uppercase tracking-widest">Add to Network</button>
            </form>
          </div>
        </div>
      )}

      {isActive && (
        <div className="fixed inset-0 z-[120] bg-red-600 flex flex-col items-center justify-center p-8 text-white text-center">
          <div className="text-6xl mb-8 animate-bounce">🚨</div>
          <h2 className="text-4xl font-black mb-4 uppercase leading-none">Broadcasting Alert</h2>
          <p className="text-lg mb-12 opacity-80 font-medium italic">Sharing GPS & Medical Data...</p>
          <div className="text-9xl font-black mb-12 tabular-nums">{countdown}</div>
          <button 
            onClick={() => setIsActive(false)}
            className="px-12 py-5 bg-white text-red-600 rounded-[32px] font-black text-xl shadow-2xl active:scale-95 transition-all"
          >
            CANCEL
          </button>
        </div>
      )}
    </>
  );
};

export default SOSButton;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, UserRole, Language, EmergencyGuide, InteractiveStep, HealthFacility, Message, EmergencyContact } from './types';
import { EMERGENCY_GUIDES, HEALTH_DIRECTORY, MOCK_BROADCASTS } from './constants';
import Layout from './components/Layout';
import SOSButton from './components/SOSButton';
import AuthScreen from './views/AuthScreen';
import { GeminiService } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [activeTab, setActiveTab] = useState('home');
  const [selectedGuide, setSelectedGuide] = useState<EmergencyGuide | null>(null);
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [showFeedback, setShowFeedback] = useState(false);
  const [symptomText, setSymptomText] = useState('');
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [checkerResult, setCheckerResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [showCamera, setShowCamera] = useState(false);

  // Directory & Chat State
  const [directoryCategory, setDirectoryCategory] = useState('All');
  const [messages, setMessages] = useState<Message[]>([]);
  const [activeChatId, setActiveChatId] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('user_profile');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Ensure new fields exist
      if (!parsed.sosContacts) parsed.sosContacts = [];
      setCurrentUser(parsed);
    }

    // Load simulated global messages
    const savedMsgs = localStorage.getItem('global_messages');
    if (savedMsgs) setMessages(JSON.parse(savedMsgs));
  }, []);

  const updateProfile = (updates: Partial<UserProfile>) => {
    if (!currentUser) return;
    const updated = { ...currentUser, ...updates };
    setCurrentUser(updated);
    localStorage.setItem('user_profile', JSON.stringify(updated));

    // Update the "global" user registry too
    const allUsers = JSON.parse(localStorage.getItem('all_registered_users') || '[]');
    const index = allUsers.findIndex((u: UserProfile) => u.id === currentUser.id);
    if (index !== -1) {
      allUsers[index] = updated;
      localStorage.setItem('all_registered_users', JSON.stringify(allUsers));
    }
  };

  const dynamicDirectory = useMemo(() => {
    const allRegistered = JSON.parse(localStorage.getItem('all_registered_users') || '[]');
    const helpers: HealthFacility[] = allRegistered
      .filter((u: UserProfile) => u.showInHelp && u.id !== currentUser?.id)
      .map((u: UserProfile) => ({
        id: u.id,
        name: u.role === UserRole.ORGANIZATION ? (u.organizationName || 'Unnamed Org') : u.fullName,
        type: u.role === UserRole.ORGANIZATION ? (u.firmType === 'Others' ? (u.otherFirmType as any || 'Organization') : u.firmType) : 'Volunteer',
        distance: 'Community Helper',
        phone: u.phone,
        address: u.address
      }));

    return [...HEALTH_DIRECTORY, ...helpers];
  }, [currentUser]);

  const filteredDirectory = useMemo(() => {
    if (directoryCategory === 'All') return dynamicDirectory;
    return dynamicDirectory.filter(item => {
      const type = item.type.toLowerCase();
      const cat = directoryCategory.toLowerCase();
      if (cat === 'volunteers') return type === 'volunteer' || type === 'caregiver' || type === 'provider';
      return type.includes(cat.slice(0, -1)) || type.includes(cat);
    });
  }, [dynamicDirectory, directoryCategory]);

  const handleGetDirections = (address: string, name: string) => {
    if (!address || address === 'National') return alert("Number Dial Required.");
    const query = encodeURIComponent(`${name}, ${address}`);
    window.open(`https://www.google.com/maps/search/?api=1&query=${query}`, '_blank');
  };

  const handleSendMessage = (text: string) => {
    if (!currentUser || !activeChatId) return;
    const newMsg: Message = {
      id: Math.random().toString(36).substr(2, 9),
      senderId: currentUser.id,
      receiverId: activeChatId,
      text,
      timestamp: Date.now(),
    };
    const updatedMsgs = [...messages, newMsg];
    setMessages(updatedMsgs);
    localStorage.setItem('global_messages', JSON.stringify(updatedMsgs));
  };

  const startChat = (receiverId: string) => {
    setActiveChatId(receiverId);
    setActiveTab('messages');
  };

  const addToSos = (facility: HealthFacility) => {
    if (!currentUser) return;
    if (currentUser.sosContacts.find(c => c.phone === facility.phone)) {
      alert("Already in your SOS network.");
      return;
    }
    const newContact: EmergencyContact = {
      id: Math.random().toString(36).substr(2, 9),
      name: facility.name,
      phone: facility.phone,
      type: 'Org'
    };
    updateProfile({ sosContacts: [...currentUser.sosContacts, newContact] });
    alert(`${facility.name} added to SOS list!`);
  };

  if (!currentUser) {
    return <AuthScreen onLogin={(user) => { 
      const profile = { ...user, sosContacts: user.sosContacts || [] };
      setCurrentUser(profile); 
      localStorage.setItem('user_profile', JSON.stringify(profile)); 
    }} />;
  }

  const activeChatPartner = dynamicDirectory.find(d => d.id === activeChatId);
  const relevantMessages = messages.filter(m => 
    (m.senderId === currentUser.id && m.receiverId === activeChatId) ||
    (m.senderId === activeChatId && m.receiverId === currentUser.id)
  );

  return (
    <Layout 
      title={activeTab === 'guides' && selectedGuide ? selectedGuide.title : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} 
      activeTab={activeTab} 
      setActiveTab={(tab) => { setActiveTab(tab); setSelectedGuide(null); if(tab !== 'messages') setActiveChatId(null); }}
      onBack={selectedGuide ? () => setSelectedGuide(null) : activeChatId ? () => setActiveChatId(null) : undefined}
    >
      {activeTab === 'home' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-black text-gray-800">Hi, {currentUser.fullName.split(' ')[0]}</h2>
              <p className="text-gray-400 text-sm font-medium">Safe & Smart Connectivity</p>
            </div>
            <button onClick={() => setActiveTab('profile')} className="w-12 h-12 bg-red-600 rounded-full flex items-center justify-center text-white text-xl font-black shadow-lg">
              {currentUser.fullName.charAt(0)}
            </button>
          </div>
          <SOSButton user={currentUser} onUpdateContacts={(contacts) => updateProfile({ sosContacts: contacts })} />
          <div className="grid grid-cols-2 gap-4">
            <QuickAction icon="🩹" label="First Aid" bg="bg-blue-50" color="text-blue-900" onClick={() => setActiveTab('guides')} />
            <QuickAction icon="🩺" label="AI Symptoms" bg="bg-purple-50" color="text-purple-900" onClick={() => setActiveTab('checker')} />
          </div>
          <section className="bg-white p-6 rounded-[32px] border-2 border-gray-50">
            <h3 className="font-black text-sm uppercase tracking-widest text-gray-400 mb-4">Latest Alerts</h3>
            {MOCK_BROADCASTS.map(alert => (
              <div key={alert.id} className="p-4 bg-orange-50 rounded-2xl border border-orange-100 mb-2 last:mb-0">
                <p className="font-bold text-gray-800 text-xs">{alert.title}</p>
                <p className="text-[10px] text-gray-500 mt-1">{alert.content}</p>
              </div>
            ))}
          </section>
        </div>
      )}

      {activeTab === 'directory' && (
        <div className="space-y-4 animate-fadeIn">
          <div className="flex gap-2 overflow-x-auto pb-4 scrollbar-hide px-1">
            {['All', 'Clinic', 'Hospital', 'Pharmacy', 'Volunteers'].map(cat => (
              <button 
                key={cat} 
                onClick={() => setDirectoryCategory(cat)}
                className={`px-6 py-2.5 rounded-full text-xs font-black transition-all border shadow-sm ${
                  directoryCategory === cat ? 'bg-red-600 text-white border-red-700 scale-105' : 'bg-white text-gray-400 border-gray-100'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>

          <div className="space-y-3">
            {filteredDirectory.length > 0 ? (
              filteredDirectory.map((place, i) => (
                <div key={i} className="bg-white p-5 rounded-[32px] border border-gray-50 shadow-sm">
                  <div className="flex items-center gap-4 mb-4">
                    <div className="w-12 h-12 bg-red-50 text-red-600 rounded-2xl flex items-center justify-center text-2xl">🏥</div>
                    <div className="flex-1">
                      <h4 className="font-black text-gray-800">{place.name}</h4>
                      <p className="text-[9px] font-bold text-red-600 uppercase">{place.type} • Community Responder</p>
                    </div>
                  </div>
                  <div className="grid grid-cols-3 gap-2">
                    <button onClick={() => addToSos(place)} className="p-3 bg-red-50 text-red-600 rounded-xl text-[9px] font-black uppercase tracking-tighter">Add SOS</button>
                    {place.id && <button onClick={() => startChat(place.id!)} className="p-3 bg-blue-50 text-blue-600 rounded-xl text-[9px] font-black uppercase tracking-tighter">Message</button>}
                    <button onClick={() => handleGetDirections(place.address, place.name)} className="p-3 bg-gray-50 text-gray-500 rounded-xl text-[9px] font-black uppercase tracking-tighter">Location</button>
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center py-24 bg-gray-50 rounded-[48px] border-2 border-dashed border-gray-200">
                <p className="text-gray-400 font-black text-sm">No {directoryCategory.toLowerCase()} registered</p>
              </div>
            )}
          </div>
        </div>
      )}

      {activeTab === 'messages' && (
        <div className="h-full flex flex-col animate-fadeIn">
          {!activeChatId ? (
