              <p className="text-gray-400 text-sm font-medium">Safe & Smart Connectivity</p>
            </div>
            <button onClick={() => setActiveTab('profile')} className="w-12 h-12 bg-red-600 rounded-full flex items-center justify-center text-white text-xl font-black shadow-lg">
              {currentUser.fullName.charAt(0)}
            </button>
          </div>
          <SOSButton user={currentUser} onUpdateContacts={(contacts) => updateProfile({ sosContacts: contacts })} />
          <div className="grid grid-cols-2 gap-4">
            <QuickAction icon="🩹" label="First Aid" bg="bg-blue-50" color="text-blue-900" onClick={() => setActiveTab('guides')} />
            <QuickAction icon="🩺" label="AI Symptoms" bg="bg-purple-50" color="text-purple-900" onClick={() => setActiveTab('checker')} />
          </div>
          <section className="bg-white p-6 rounded-[32px] border-2 border-gray-50">
            <h3 className="font-black text-sm uppercase tracking-widest text-gray-400 mb-4">Latest Alerts</h3>
