              </div>
              <form onSubmit={(e) => { e.preventDefault(); const input = e.currentTarget.msg; if(input.value) { handleSendMessage(input.value); input.value = ''; } }} className="flex gap-2">
                <input name="msg" placeholder="Type a message..." className="flex-1 p-4 bg-gray-50 rounded-2xl border-none outline-none text-sm" />
                <button type="submit" className="w-14 h-14 bg-red-600 text-white rounded-2xl flex items-center justify-center text-xl">↗️</button>
              </form>
            </div>
          )}
        </div>
      )}

      {activeTab === 'guides' && (
        <div className="animate-fadeIn">
          {!selectedGuide ? (
            <div className="grid grid-cols-2 gap-4">
              {EMERGENCY_GUIDES.map(guide => (
                <button key={guide.id} onClick={() => { setSelectedGuide(guide); speakGuide(guide, guide.steps[0]); }} className="bg-white p-6 rounded-[32px] border-2 border-gray-50 shadow-sm flex flex-col items-center hover:border-red-200 transition-all active:scale-95">
                  <span className="text-4xl mb-3">{guide.icon}</span>
                  <span className="font-bold text-gray-800 text-sm text-center">{guide.title}</span>
                </button>
              ))}
            </div>
          ) : (
            <div className="space-y-6">
              <div className="relative overflow-hidden rounded-[32px] shadow-xl">
                <img src={selectedGuide.image} className="w-full h-52 object-cover" />
                <div className="absolute bottom-4 left-4 bg-red-600 text-white px-4 py-1.5 rounded-full text-[10px] font-black">Step {currentStepIndex + 1}</div>
              </div>
              <h2 className="text-2xl font-black text-gray-900 leading-tight">{selectedGuide.steps[currentStepIndex].text}</h2>
              <button onClick={() => speakGuide(selectedGuide, selectedGuide.steps[currentStepIndex])} className="p-4 bg-red-50 text-red-600 rounded-2xl font-black text-xs">🔊 READ ALOUD</button>
              <button onClick={() => currentStepIndex < selectedGuide.steps.length - 1 ? setCurrentStepIndex(currentStepIndex+1) : setSelectedGuide(null)} className="w-full py-6 bg-red-600 text-white rounded-[32px] font-black text-xl uppercase shadow-xl">Done</button>
            </div>
          )}
        </div>
      )}

      {activeTab === 'checker' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-[40px] border-2 border-gray-50 shadow-xl space-y-4">
            <h3 className="text-xl font-black text-gray-800">AI Symptom Check</h3>
            <textarea value={symptomText} onChange={(e) => setSymptomText(e.target.value)} placeholder="Describe what's happening..." className="w-full h-32 p-5 bg-gray-50 rounded-3xl border-0 text-sm resize-none" />
            <button onClick={checkSymptoms} disabled={loading} className="w-full py-5 bg-red-600 text-white rounded-2xl font-black shadow-lg">
              {loading ? 'Analyzing...' : 'Submit Symptoms'}
            </button>
          </div>
          {checkerResult && (
            <div className="bg-white p-8 rounded-[40px] shadow-2xl animate-slideUp border border-gray-50">
              <p className="text-gray-600 font-medium italic mb-6">"{checkerResult.advice}"</p>
              <div className="space-y-3">
                {checkerResult.steps.map((s: string, i: number) => (
                  <div key={i} className="flex gap-3 text-sm text-gray-700 bg-gray-50 p-4 rounded-2xl font-medium">
                    <span className="text-red-500 font-black">{i+1}.</span>
                    <span>{s}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'profile' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="text-center p-10 bg-gray-50 rounded-[48px]">
            <div className="w-24 h-24 bg-red-600 text-white text-5xl font-black flex items-center justify-center rounded-full mx-auto mb-6 shadow-2xl border-4 border-white">
              {currentUser.fullName.charAt(0)}
            </div>
            <h2 className="text-2xl font-black text-gray-800">{currentUser.fullName}</h2>
            <p className="text-gray-400 text-xs font-bold uppercase tracking-widest">{currentUser.role}</p>
          </div>
          <div className="bg-white p-8 rounded-[40px] border-2 border-gray-50 shadow-sm space-y-6">
            <InfoRow label="Email" value={currentUser.email} />
            <InfoRow label="Phone" value={currentUser.phone} />
            <InfoRow label="SOS Members" value={`${currentUser.sosContacts.length} people`} />
          </div>
          <button onClick={handleLogout} className="w-full py-5 bg-gray-100 text-gray-400 rounded-3xl font-black uppercase text-xs tracking-widest">Sign Out</button>
        </div>
      )}
    </Layout>
  );
};

const QuickAction: React.FC<{ icon: string; label: string; bg: string; color: string; onClick: () => void }> = ({ icon, label, bg, color, onClick }) => (
  <button onClick={onClick} className={`${bg} p-8 rounded-[40px] border border-transparent flex flex-col items-center shadow-sm active:scale-95 transition-all`}>
    <span className="text-4xl mb-3">{icon}</span>
    <span className={`font-black uppercase text-[9px] tracking-widest ${color}`}>{label}</span>
  </button>
);

const InfoRow: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="flex flex-col">
    <span className="text-[8px] font-black text-gray-300 uppercase tracking-widest mb-1">{label}</span>
    <span className="text-sm font-bold text-gray-700">{value}</span>
  </div>
);

export default App;

export enum UserRole {
  PATIENT = 'PATIENT',
  CAREGIVER = 'CAREGIVER',
  ORGANIZATION = 'ORGANIZATION'
}

export enum Language {
  ENGLISH = 'en',
  HAUSA = 'ha',
  YORUBA = 'yo',
  IGBO = 'ig'
}

export interface EmergencyContact {
  id: string;
  name: string;
  phone: string;
  type: 'Family' | 'Org' | 'National';
}

export interface Message {
  id: string;
  senderId: string;
  receiverId: string;
  text: string;
  timestamp: number;
}

export interface UserProfile {
  id: string;
  role: UserRole;
  fullName: string;
  username?: string;
  profilePicture?: string; // Base64 string
  email: string;
  password?: string;
  phone: string;
  age?: number;
  gender?: string;
  genotype?: string;
  bloodGroup?: string;
  height?: string;
  weight?: string;
  address: string;
  preferredLanguage: Language;
  healthChallenges?: string;
  emergencyContact?: string; 
  sosContacts: EmergencyContact[];
  showInHelp: boolean;
  medicalSpecialty?: string;
  patientInteractionMethod?: string;
  organizationName?: string;
  firmType?: 'Clinic' | 'Hospital' | 'Pharmacy' | 'Others';
  otherFirmType?: string;
}

export interface InteractiveStep {
  text: string;
  feedback?: string;
  actionRequired?: string;
  critical?: boolean;
}

export interface EmergencyGuide {
  id: string;
  title: string;
  icon: string;
  steps: InteractiveStep[];
  image: string;
  furtherHelp: string;
  whenToCallSOS: string;
}

export interface HealthFacility {
  id?: string;
  name: string;
  type: string;
  distance: string;
  phone: string;
  address: string;
  profilePicture?: string;
}

export interface Broadcast {
  id: string;
  title: string;
  content: string;
  date: string;
  priority: 'low' | 'high';
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, UserRole, Language, EmergencyGuide, InteractiveStep, HealthFacility, Message, EmergencyContact } from './types';
import { EMERGENCY_GUIDES, HEALTH_DIRECTORY, MOCK_BROADCASTS } from './constants';
import Layout from './components/Layout';
import SOSButton from './components/SOSButton';
import AuthScreen from './views/AuthScreen';
import { GeminiService } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [activeTab, setActiveTab] = useState('home');
  const [selectedGuide, setSelectedGuide] = useState<EmergencyGuide | null>(null);
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [showFeedback, setShowFeedback] = useState(false);
  const [symptomText, setSymptomText] = useState('');
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [checkerResult, setCheckerResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [showCamera, setShowCamera] = useState(false);

  // Profile Editing State
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [editData, setEditData] = useState<Partial<UserProfile>>({});

  // Directory & Chat State
  const [directoryCategory, setDirectoryCategory] = useState('All');
  const [messages, setMessages] = useState<Message[]>([]);
  const [activeChatId, setActiveChatId] = useState<string | null>(null);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('user_profile');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.sosContacts) parsed.sosContacts = [];
      setCurrentUser(parsed);
    }
    const savedMsgs = localStorage.getItem('global_messages');
    if (savedMsgs) setMessages(JSON.parse(savedMsgs));
  }, []);

  const updateProfile = (updates: Partial<UserProfile>) => {
    if (!currentUser) return;
    const updated = { ...currentUser, ...updates };
    setCurrentUser(updated);
    localStorage.setItem('user_profile', JSON.stringify(updated));

    const allUsers = JSON.parse(localStorage.getItem('all_registered_users') || '[]');
    const index = allUsers.findIndex((u: UserProfile) => u.id === currentUser.id);
    if (index !== -1) {
      allUsers[index] = updated;
      localStorage.setItem('all_registered_users', JSON.stringify(allUsers));
    }
  };

  const handleSaveProfile = () => {
    updateProfile(editData);
    setIsEditingProfile(false);
  };

  const handleProfilePictureClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setEditData(prev => ({ ...prev, profilePicture: base64 }));
      };
      reader.readAsDataURL(file);
    }
  };

  const dynamicDirectory = useMemo(() => {
    const allRegistered = JSON.parse(localStorage.getItem('all_registered_users') || '[]');
    const helpers: HealthFacility[] = allRegistered
      .filter((u: UserProfile) => u.showInHelp && u.id !== currentUser?.id)
      .map((u: UserProfile) => ({
        id: u.id,
        name: u.role === UserRole.ORGANIZATION ? (u.organizationName || 'Unnamed Org') : u.fullName,
        type: u.role === UserRole.ORGANIZATION ? (u.firmType === 'Others' ? (u.otherFirmType as any || 'Organization') : u.firmType) : 'Volunteer',
        distance: 'Community Helper',
        phone: u.phone,
        address: u.address,
        profilePicture: u.profilePicture
      }));

    return [...HEALTH_DIRECTORY, ...helpers];
  }, [currentUser]);

  const filteredDirectory = useMemo(() => {
    if (directoryCategory === 'All') return dynamicDirectory;
    return dynamicDirectory.filter(item => {
      const type = item.type.toLowerCase();
      const cat = directoryCategory.toLowerCase();
      if (cat === 'volunteers') return type === 'volunteer' || type === 'caregiver' || type === 'provider';
      return type.includes(cat.slice(0, -1)) || type.includes(cat);
    });
  }, [dynamicDirectory, directoryCategory]);

  const handleGetDirections = (address: string, name: string) => {
    if (!address || address === 'National') return alert("Number Dial Required.");
    const query = encodeURIComponent(`${name}, ${address}`);
    window.open(`https://www.google.com/maps/search/?api=1&query=${query}`, '_blank');
  };

  const handleSendMessage = (text: string) => {
    if (!currentUser || !activeChatId) return;
    const newMsg: Message = {
      id: Math.random().toString(36).substr(2, 9),
      senderId: currentUser.id,
      receiverId: activeChatId,
      text,
      timestamp: Date.now(),
    };
    const updatedMsgs = [...messages, newMsg];
    setMessages(updatedMsgs);
    localStorage.setItem('global_messages', JSON.stringify(updatedMsgs));
  };

  const startChat = (receiverId: string) => {
    setActiveChatId(receiverId);
    setActiveTab('messages');
  };

  const addToSos = (facility: HealthFacility) => {
    if (!currentUser) return;
    if (currentUser.sosContacts.find(c => c.phone === facility.phone)) {
      alert("Already in your SOS network.");
      return;
    }
    const newContact: EmergencyContact = {
      id: Math.random().toString(36).substr(2, 9),
      name: facility.name,
      phone: facility.phone,
      type: 'Org'
    };
    updateProfile({ sosContacts: [...currentUser.sosContacts, newContact] });
    alert(`${facility.name} added to SOS list!`);
  };

  const speakGuide = async (guide: EmergencyGuide, step: InteractiveStep) => {
    try {
      await GeminiService.speakText(`${guide.title}. Step: ${step.text}`);
    } catch (error) {
      console.error("Audio playback error:", error);
    }
  };

  const checkSymptoms = async () => {
    if (!symptomText.trim() && !capturedImage) {
      alert("Please describe symptoms or provide an image.");
      return;
    }
    setLoading(true);
    try {
      const result = await GeminiService.checkSymptoms(symptomText, capturedImage || undefined);
      setCheckerResult(result);
    } catch (error) {
      console.error("AI check error:", error);
      alert("Analysis failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('user_profile');
    setActiveTab('home');
    setActiveChatId(null);
  };

  if (!currentUser) {
    return <AuthScreen onLogin={(user) => { 
      const profile = { ...user, sosContacts: user.sosContacts || [] };
      setCurrentUser(profile); 
      localStorage.setItem('user_profile', JSON.stringify(profile)); 
    }} />;
  }

  const activeChatPartner = dynamicDirectory.find(d => d.id === activeChatId);
  const relevantMessages = messages.filter(m => 
    (m.senderId === currentUser.id && m.receiverId === activeChatId) ||
    (m.senderId === activeChatId && m.receiverId === currentUser.id)
  );

  return (
    <Layout 
      title={activeTab === 'guides' && selectedGuide ? selectedGuide.title : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} 
      activeTab={activeTab} 
      setActiveTab={(tab) => { setActiveTab(tab); setSelectedGuide(null); if(tab !== 'messages') setActiveChatId(null); setIsEditingProfile(false); }}
      onBack={selectedGuide ? () => setSelectedGuide(null) : activeChatId ? () => setActiveChatId(null) : isEditingProfile ? () => setIsEditingProfile(false) : undefined}
    >
      {activeTab === 'home' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-black text-gray-800">Hi, {currentUser.fullName.split(' ')[0]}</h2>
              <p className="text-gray-400 text-sm font-medium">Safe & Smart Connectivity</p>
            </div>
            <button onClick={() => setActiveTab('profile')} className="w-14 h-14 bg-red-600 rounded-full flex items-center justify-center text-white text-xl font-black shadow-lg overflow-hidden border-2 border-white">
              {currentUser.profilePicture ? <img src={currentUser.profilePicture} className="w-full h-full object-cover" /> : currentUser.fullName.charAt(0)}
            </button>
          </div>
          <SOSButton user={currentUser} onUpdateContacts={(contacts) => updateProfile({ sosContacts: contacts })} />
          <div className="grid grid-cols-2 gap-4">
            <QuickAction icon="🩹" label="First Aid" bg="bg-blue-50" color="text-blue-900" onClick={() => setActiveTab('guides')} />
            <QuickAction icon="🩺" label="AI Symptoms" bg="bg-purple-50" color="text-purple-900" onClick={() => setActiveTab('checker')} />
          </div>
          <section className="bg-white p-6 rounded-[32px] border-2 border-gray-50">
            <h3 className="font-black text-sm uppercase tracking-widest text-gray-400 mb-4">Latest Alerts</h3>
            {MOCK_BROADCASTS.map(alert => (
              <div key={alert.id} className="p-4 bg-orange-50 rounded-2xl border border-orange-100 mb-2 last:mb-0">
                <p className="font-bold text-gray-800 text-xs">{alert.title}</p>
                <p className="text-[10px] text-gray-500 mt-1">{alert.content}</p>
              </div>
            ))}
          </section>
        </div>
      )}

      {activeTab === 'directory' && (
        <div className="space-y-4 animate-fadeIn">
          <div className="flex gap-2 overflow-x-auto pb-4 scrollbar-hide px-1">
            {['All', 'Clinic', 'Hospital', 'Pharmacy', 'Volunteers'].map(cat => (
              <button 
                key={cat} 
                onClick={() => setDirectoryCategory(cat)}
                className={`px-6 py-2.5 rounded-full text-xs font-black transition-all border shadow-sm ${
                  directoryCategory === cat ? 'bg-red-600 text-white border-red-700 scale-105' : 'bg-white text-gray-400 border-gray-100'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>

          <div className="space-y-3">
            {filteredDirectory.length > 0 ? (
              filteredDirectory.map((place, i) => (
                <div key={i} className="bg-white p-5 rounded-[32px] border border-gray-50 shadow-sm">
                  <div className="flex items-center gap-4 mb-4">
                    <div className="w-12 h-12 bg-red-50 text-red-600 rounded-2xl flex items-center justify-center text-2xl overflow-hidden">
                      {place.profilePicture ? <img src={place.profilePicture} className="w-full h-full object-cover" /> : '🏥'}
                    </div>
                    <div className="flex-1">
                      <h4 className="font-black text-gray-800">{place.name}</h4>
                      <p className="text-[9px] font-bold text-red-600 uppercase">{place.type} • Community Responder</p>
                    </div>
                  </div>
                  <div className="grid grid-cols-3 gap-2">
                    <button onClick={() => addToSos(place)} className="p-3 bg-red-50 text-red-600 rounded-xl text-[9px] font-black uppercase tracking-tighter">Add SOS</button>
                    {place.id && <button onClick={() => startChat(place.id!)} className="p-3 bg-blue-50 text-blue-600 rounded-xl text-[9px] font-black uppercase tracking-tighter">Message</button>}
                    <button onClick={() => handleGetDirections(place.address, place.name)} className="p-3 bg-gray-50 text-gray-500 rounded-xl text-[9px] font-black uppercase tracking-tighter">Location</button>
                  </div>
                </div>
              ))
            ) : (
              <div className="text-center py-24 bg-gray-50 rounded-[48px] border-2 border-dashed border-gray-200">
                <p className="text-gray-400 font-black text-sm">No {directoryCategory.toLowerCase()} registered</p>
              </div>
            )}
          </div>
        </div>
      )}

      {activeTab === 'messages' && (
        <div className="h-full flex flex-col animate-fadeIn">
          {!activeChatId ? (
            <div className="space-y-3">
              <h3 className="font-black text-xl mb-4 px-2">Conversations</h3>
              {dynamicDirectory.length > 0 ? dynamicDirectory.map(user => (
                <button key={user.id} onClick={() => user.id && setActiveChatId(user.id)} className="w-full flex items-center gap-4 p-5 bg-white rounded-3xl border border-gray-50 shadow-sm active:scale-95 transition-all">
                  <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center text-xl overflow-hidden">
                    {user.profilePicture ? <img src={user.profilePicture} className="w-full h-full object-cover" /> : '👤'}
                  </div>
                  <div className="text-left">
                    <p className="font-black text-gray-800">{user.name}</p>
                    <p className="text-[10px] text-gray-400 font-bold uppercase">{user.type}</p>
                  </div>
                </button>
              )) : <p className="text-center text-gray-400 text-sm mt-10">No contacts available to message.</p>}
            </div>
          ) : (
            <div className="flex flex-col h-[calc(100vh-220px)]">
              <div className="flex items-center gap-3 pb-4 mb-4 border-b border-gray-100">
                <div className="w-10 h-10 bg-red-100 rounded-full flex items-center justify-center text-lg overflow-hidden">
                  {activeChatPartner?.profilePicture ? <img src={activeChatPartner.profilePicture} className="w-full h-full object-cover" /> : '👤'}
                </div>
                <div>
                  <p className="font-black text-sm">{activeChatPartner?.name}</p>
                  <p className="text-[8px] text-gray-400 uppercase font-black tracking-widest">{activeChatPartner?.type}</p>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto space-y-4 pb-4">
                {relevantMessages.map(m => (
                  <div key={m.id} className={`max-w-[80%] p-4 rounded-3xl ${m.senderId === currentUser.id ? 'bg-red-600 text-white ml-auto rounded-tr-none' : 'bg-gray-100 text-gray-800 rounded-tl-none'}`}>
                    <p className="text-sm font-medium">{m.text}</p>
                  </div>
                ))}
              </div>
              <form onSubmit={(e) => { e.preventDefault(); const input = e.currentTarget.msg; if(input.value) { handleSendMessage(input.value); input.value = ''; } }} className="flex gap-2">
                <input name="msg" placeholder="Type a message..." className="flex-1 p-4 bg-gray-50 rounded-2xl border-none outline-none text-sm" />
                <button type="submit" className="w-14 h-14 bg-red-600 text-white rounded-2xl flex items-center justify-center text-xl">↗️</button>
              </form>
            </div>
          )}
        </div>
      )}

      {activeTab === 'profile' && (
        <div className="space-y-6 animate-fadeIn">
          {!isEditingProfile ? (
            <>
              <div className="text-center p-10 bg-gray-50 rounded-[48px]">
                <div className="w-24 h-24 bg-red-600 text-white text-5xl font-black flex items-center justify-center rounded-full mx-auto mb-6 shadow-2xl border-4 border-white overflow-hidden">
                  {currentUser.profilePicture ? <img src={currentUser.profilePicture} className="w-full h-full object-cover" /> : currentUser.fullName.charAt(0)}
                </div>
                <h2 className="text-2xl font-black text-gray-800">{currentUser.fullName}</h2>
                {currentUser.username && <p className="text-red-600 text-xs font-black">@{currentUser.username}</p>}
                <p className="text-gray-400 text-[10px] font-bold uppercase tracking-widest mt-2">{currentUser.role}</p>
                <button 
                  onClick={() => { setEditData(currentUser); setIsEditingProfile(true); }}
                  className="mt-6 px-8 py-2.5 bg-white text-gray-800 rounded-full text-[10px] font-black uppercase shadow-sm border border-gray-100"
                >
                  Edit Profile
                </button>
              </div>
              <div className="bg-white p-8 rounded-[40px] border-2 border-gray-50 shadow-sm space-y-6">
                <InfoRow label="Email Account" value={currentUser.email} />
                <InfoRow label="Phone Contact" value={currentUser.phone} />
                <InfoRow label="Primary Address" value={currentUser.address} />
                <InfoRow label="SOS Members" value={`${currentUser.sosContacts.length} people configured`} />
              </div>
              <button onClick={handleLogout} className="w-full py-5 bg-gray-100 text-gray-400 rounded-3xl font-black uppercase text-[10px] tracking-widest">Sign Out</button>
            </>
          ) : (
            <div className="space-y-6 animate-slideUp">
              <div className="text-center mb-8 relative">
                <div 
                  onClick={handleProfilePictureClick} 
                  className="w-28 h-28 bg-gray-100 rounded-full mx-auto relative cursor-pointer border-4 border-white shadow-xl overflow-hidden flex items-center justify-center group"
                >
                  {editData.profilePicture ? (
                    <img src={editData.profilePicture} className="w-full h-full object-cover group-hover:opacity-80 transition-opacity" />
                  ) : (
                    <span className="text-4xl text-gray-300">📷</span>
                  )}
                  <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                    <span className="text-white text-xs font-black uppercase">Change</span>
                  </div>
                </div>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
                <p className="mt-3 text-[10px] text-gray-400 font-black uppercase tracking-widest">Update Photo</p>
              </div>

              <div className="bg-white p-8 rounded-[40px] border-2 border-gray-100 space-y-5 shadow-inner">
                <EditInput label="Display Name" value={editData.fullName} onChange={(val) => setEditData({...editData, fullName: val})} />
                <EditInput label="Username (@)" value={editData.username} onChange={(val) => setEditData({...editData, username: val.replace(/\s/g, '').toLowerCase()})} placeholder="unique_handle" />
                <EditInput label="Phone Number" value={editData.phone} onChange={(val) => setEditData({...editData, phone: val})} />
                <EditInput label="Address" value={editData.address} onChange={(val) => setEditData({...editData, address: val})} />
                {currentUser.role === UserRole.ORGANIZATION && (
                  <EditInput label="Organization Name" value={editData.organizationName} onChange={(val) => setEditData({...editData, organizationName: val})} />
                )}
              </div>

              <div className="flex gap-4">
                <button onClick={() => setIsEditingProfile(false)} className="flex-1 py-5 bg-gray-100 text-gray-500 rounded-3xl font-black uppercase text-xs">Cancel</button>
                <button onClick={handleSaveProfile} className="flex-1 py-5 bg-red-600 text-white rounded-3xl font-black uppercase text-xs shadow-lg">Save Changes</button>
              </div>
            </div>
          )}
        </div>
      )}
    </Layout>
  );
};

const QuickAction: React.FC<{ icon: string; label: string; bg: string; color: string; onClick: () => void }> = ({ icon, label, bg, color, onClick }) => (
  <button onClick={onClick} className={`${bg} p-8 rounded-[40px] border border-transparent flex flex-col items-center shadow-sm active:scale-95 transition-all`}>
    <span className="text-4xl mb-3">{icon}</span>
    <span className={`font-black uppercase text-[9px] tracking-widest ${color}`}>{label}</span>
  </button>
);

const InfoRow: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="flex flex-col">
    <span className="text-[8px] font-black text-gray-300 uppercase tracking-widest mb-1">{label}</span>
    <span className="text-sm font-bold text-gray-700">{value}</span>
  </div>
);

const EditInput: React.FC<{ label: string; value: string | undefined; onChange: (v: string) => void; placeholder?: string }> = ({ label, value, onChange, placeholder }) => (
  <div className="space-y-1">
    <label className="text-[8px] font-black text-red-600 uppercase tracking-widest ml-1">{label}</label>
    <input 
      type="text" 
      value={value || ''} 
      onChange={(e) => onChange(e.target.value)}
      placeholder={placeholder}
      className="w-full p-4 bg-gray-50 rounded-2xl border-none outline-none text-sm font-medium focus:ring-2 focus:ring-red-100" 
    />
  </div>
);

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, UserRole, Language, EmergencyGuide, InteractiveStep, HealthFacility, Message, EmergencyContact } from './types';
import { EMERGENCY_GUIDES, HEALTH_DIRECTORY, MOCK_BROADCASTS } from './constants';
import Layout from './components/Layout';
import SOSButton from './components/SOSButton';
import AuthScreen from './views/AuthScreen';
import { GeminiService } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [activeTab, setActiveTab] = useState('home');
  const [selectedGuide, setSelectedGuide] = useState<EmergencyGuide | null>(null);
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [symptomText, setSymptomText] = useState('');
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [checkerResult, setCheckerResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  // Profile & Directory State
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [editData, setEditData] = useState<Partial<UserProfile>>({});
  const [directoryCategory, setDirectoryCategory] = useState('All');
  const [directorySearch, setDirectorySearch] = useState('');
  const [selectedPatientProfile, setSelectedPatientProfile] = useState<UserProfile | null>(null);

  // Messaging State
  const [messages, setMessages] = useState<Message[]>([]);
  const [activeChatId, setActiveChatId] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('user_profile');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.sosContacts) parsed.sosContacts = [];
      setCurrentUser(parsed);
    }
    const savedMsgs = localStorage.getItem('global_messages');
    if (savedMsgs) setMessages(JSON.parse(savedMsgs));
  }, []);

  const updateProfile = (updates: Partial<UserProfile>) => {
    if (!currentUser) return;
    const updated = { ...currentUser, ...updates };
    setCurrentUser(updated);
    localStorage.setItem('user_profile', JSON.stringify(updated));

    const allUsers = JSON.parse(localStorage.getItem('all_registered_users') || '[]');
    const index = allUsers.findIndex((u: UserProfile) => u.id === currentUser.id);
    if (index !== -1) {
      allUsers[index] = updated;
      localStorage.setItem('all_registered_users', JSON.stringify(allUsers));
    }
  };

  const handleSaveProfile = () => {
    updateProfile(editData);
    setIsEditingProfile(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setEditData(prev => ({ ...prev, profilePicture: base64 }));
      };
      reader.readAsDataURL(file);
    }
  };

  const dynamicDirectoryItems = useMemo(() => {
    const allRegistered = JSON.parse(localStorage.getItem('all_registered_users') || '[]');

    if (currentUser?.role === UserRole.PATIENT) {
      const helpers: HealthFacility[] = allRegistered
        .filter((u: UserProfile) => u.showInHelp && u.id !== currentUser?.id && (u.role === UserRole.ORGANIZATION || u.role === UserRole.CAREGIVER))
        .map((u: UserProfile) => ({
          id: u.id,
          name: u.role === UserRole.ORGANIZATION ? (u.organizationName || 'Unnamed Org') : u.fullName,
          type: u.role === UserRole.ORGANIZATION ? (u.firmType === 'Others' ? (u.otherFirmType as any || 'Organization') : u.firmType) : 'Volunteer',
          distance: 'Community Helper',
          phone: u.phone,
          address: u.address,
          profilePicture: u.profilePicture
        }));
      return [...HEALTH_DIRECTORY, ...helpers];
    } else {
      // For Responders: Show Patients
      return allRegistered.filter((u: UserProfile) => u.role === UserRole.PATIENT && u.showInHelp);
    }
  }, [currentUser]);

  const filteredDirectory = useMemo(() => {
    const items = dynamicDirectoryItems.filter(item => {
      const name = (item as any).fullName || (item as any).name || (item as any).organizationName || "";
      return name.toLowerCase().includes(directorySearch.toLowerCase());
    });

    if (currentUser?.role !== UserRole.PATIENT) return items;

    if (directoryCategory === 'All') return items;
    return items.filter((item: any) => {
      const type = item.type?.toLowerCase() || "";
      const cat = directoryCategory.toLowerCase();
      if (cat === 'volunteers') return type === 'volunteer' || type === 'caregiver' || type === 'provider';
      return type.includes(cat.slice(0, -1)) || type.includes(cat);
    });
  }, [dynamicDirectoryItems, directoryCategory, directorySearch, currentUser]);

  const handleSendMessage = (text: string) => {
    if (!currentUser || !activeChatId) return;
    const newMsg: Message = {
      id: Math.random().toString(36).substr(2, 9),
      senderId: currentUser.id,
      receiverId: activeChatId,
      text,
      timestamp: Date.now(),
    };
    const updatedMsgs = [...messages, newMsg];
    setMessages(updatedMsgs);
    localStorage.setItem('global_messages', JSON.stringify(updatedMsgs));
  };

  const speakGuide = async (guide: EmergencyGuide, step: InteractiveStep) => {
    try { await GeminiService.speakText(`${guide.title}. Step: ${step.text}`); } catch (e) {}
  };

  const checkSymptoms = async () => {
    if (!symptomText.trim()) return alert("Please describe symptoms.");
    setLoading(true);
    try {
      const result = await GeminiService.checkSymptoms(symptomText);
      setCheckerResult(result);
    } catch (e) { alert("Analysis failed."); } finally { setLoading(false); }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('user_profile');
    setActiveTab('home');
  };

  if (!currentUser) return <AuthScreen onLogin={setCurrentUser} />;

  return (
    <Layout 
      title={activeTab === 'guides' && selectedGuide ? selectedGuide.title : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} 
      activeTab={activeTab} 
      setActiveTab={(tab) => { 
        setActiveTab(tab); 
        setSelectedGuide(null); 
        setIsEditingProfile(false); 
        setSelectedPatientProfile(null);
        if(tab !== 'messages') setActiveChatId(null);
      }}
      onBack={selectedGuide ? () => setSelectedGuide(null) : activeChatId ? () => setActiveChatId(null) : isEditingProfile ? () => setIsEditingProfile(false) : selectedPatientProfile ? () => setSelectedPatientProfile(null) : undefined}
    >
      {activeTab === 'home' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-black text-gray-800">Hi, {currentUser.fullName.split(' ')[0]}</h2>
              <p className="text-gray-400 text-sm font-medium">Safe & Smart Help</p>
            </div>
            <button onClick={() => setActiveTab('profile')} className="w-14 h-14 bg-red-600 rounded-full flex items-center justify-center text-white text-xl font-black shadow-lg overflow-hidden border-2 border-white">
              {currentUser.profilePicture ? <img src={currentUser.profilePicture} className="w-full h-full object-cover" /> : currentUser.fullName.charAt(0)}
            </button>
          </div>
          <SOSButton user={currentUser} onUpdateContacts={(contacts) => updateProfile({ sosContacts: contacts })} />
          <div className="grid grid-cols-2 gap-4">
            <QuickAction icon="🩹" label="First Aid" bg="bg-blue-50" color="text-blue-900" onClick={() => setActiveTab('guides')} />
            <QuickAction icon="🩺" label="AI Symptoms" bg="bg-purple-50" color="text-purple-900" onClick={() => setActiveTab('checker')} />
          </div>
          <section className="bg-white p-6 rounded-[32px] border-2 border-gray-50">
            <h3 className="font-black text-sm uppercase tracking-widest text-gray-400 mb-4">Latest Alerts</h3>
            {MOCK_BROADCASTS.map(alert => (
              <div key={alert.id} className="p-4 bg-orange-50 rounded-2xl border border-orange-100 mb-2 last:mb-0">
                <p className="font-bold text-gray-800 text-xs">{alert.title}</p>
                <p className="text-[10px] text-gray-500 mt-1">{alert.content}</p>
              </div>
            ))}
          </section>
        </div>
      )}

      {activeTab === 'directory' && (
        <div className="space-y-4 animate-fadeIn">
          <div className="relative">
            <input 
              type="text" 
              placeholder={currentUser.role === UserRole.PATIENT ? "Search Health Facilities..." : "Search Community Patients..."}
              value={directorySearch}
              onChange={(e) => setDirectorySearch(e.target.value)}
              className="w-full p-4 bg-gray-50 rounded-2xl border-none text-sm font-medium focus:ring-2 focus:ring-red-100 outline-none"
            />
            <span className="absolute right-4 top-4 opacity-30">🔍</span>
          </div>

          {currentUser.role === UserRole.PATIENT && (
            <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide px-1">
              {['All', 'Clinic', 'Hospital', 'Pharmacy', 'Volunteers'].map(cat => (
                <button 
                  key={cat} 
                  onClick={() => setDirectoryCategory(cat)}
                  className={`px-6 py-2 rounded-full text-[10px] font-black transition-all border ${directoryCategory === cat ? 'bg-red-600 text-white border-red-700' : 'bg-white text-gray-400 border-gray-100'}`}
                >
                  {cat}
                </button>
              ))}
            </div>
          )}

          <div className="space-y-3">
            {selectedPatientProfile ? (
              <div className="animate-slideUp space-y-6">
                <div className="bg-red-50 p-6 rounded-[32px] border border-red-100 flex flex-col items-center">
                  <div className="w-24 h-24 bg-red-600 rounded-full mb-4 flex items-center justify-center text-white text-4xl font-black overflow-hidden border-4 border-white shadow-xl">
                    {selectedPatientProfile.profilePicture ? <img src={selectedPatientProfile.profilePicture} className="w-full h-full object-cover" /> : selectedPatientProfile.fullName.charAt(0)}
                  </div>
                  <h3 className="text-xl font-black text-red-900">{selectedPatientProfile.fullName}</h3>
                  <p className="text-[10px] font-black text-red-600 uppercase tracking-[2px]">{selectedPatientProfile.gender} • Age {selectedPatientProfile.age}</p>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <MedicalMetric icon="🩸" label="Blood Group" value={selectedPatientProfile.bloodGroup || 'Not set'} />
                  <MedicalMetric icon="🧬" label="Genotype" value={selectedPatientProfile.genotype || 'Not set'} />
                </div>

                <div className="bg-white p-6 rounded-[32px] border border-gray-100 shadow-sm space-y-4">
                  <div>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Health Challenges</p>
                    <p className="text-sm font-medium text-gray-700">{selectedPatientProfile.healthChallenges || 'None reported'}</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Address</p>
                    <p className="text-sm font-medium text-gray-700">{selectedPatientProfile.address}</p>
                  </div>
                </div>

                <div className="flex gap-4">
                  <button onClick={() => window.open(`tel:${selectedPatientProfile.phone}`)} className="flex-1 py-5 bg-red-600 text-white rounded-2xl font-black shadow-lg">CALL NOW</button>
                  <button onClick={() => startChat(selectedPatientProfile.id)} className="flex-1 py-5 bg-blue-600 text-white rounded-2xl font-black shadow-lg">MESSAGE</button>
                </div>
              </div>
            ) : filteredDirectory.map((item: any, i) => (
              <div key={i} className="bg-white p-5 rounded-[32px] border border-gray-50 shadow-sm flex items-center gap-4 active:scale-[0.98] transition-all" onClick={() => currentUser.role !== UserRole.PATIENT ? setSelectedPatientProfile(item) : null}>
                <div className="w-14 h-14 bg-red-50 text-red-600 rounded-2xl flex items-center justify-center text-2xl overflow-hidden font-black">
                  {item.profilePicture ? <img src={item.profilePicture} className="w-full h-full object-cover" /> : (item.role === UserRole.PATIENT ? item.fullName.charAt(0) : '🏥')}
                </div>
                <div className="flex-1">
                  <h4 className="font-black text-gray-800 text-sm">{item.fullName || item.name || item.organizationName}</h4>
                  <p className="text-[9px] font-bold text-red-600 uppercase tracking-widest">{item.type || (item.role === UserRole.PATIENT ? `Patient • ${item.bloodGroup}` : 'Responder')}</p>
                </div>
                {currentUser.role === UserRole.PATIENT && (
                  <button onClick={(e) => { e.stopPropagation(); startChat(item.id); }} className="p-3 bg-blue-50 text-blue-600 rounded-xl text-xs">💬</button>
                )}
              </div>
            ))}
            {filteredDirectory.length === 0 && (
              <div className="text-center py-20 opacity-30 font-black italic">No records found</div>
            )}
          </div>
        </div>
      )}

      {activeTab === 'guides' && (
        <div className="animate-fadeIn">
          {!selectedGuide ? (
            <div className="grid grid-cols-2 gap-4">
              {EMERGENCY_GUIDES.map(guide => (
                <button key={guide.id} onClick={() => { setSelectedGuide(guide); setCurrentStepIndex(0); speakGuide(guide, guide.steps[0]); }} className="bg-white p-6 rounded-[32px] border-2 border-gray-50 shadow-sm flex flex-col items-center active:scale-95 transition-all">
                  <span className="text-4xl mb-3">{guide.icon}</span>
                  <span className="font-bold text-gray-800 text-[10px] text-center uppercase tracking-widest">{guide.title}</span>
                </button>
              ))}
            </div>
          ) : (
            <div className="space-y-6">
              <div className="relative overflow-hidden rounded-[32px] shadow-xl">
                <img src={selectedGuide.image} className="w-full h-52 object-cover" />
                <div className="absolute bottom-4 left-4 bg-red-600 text-white px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest">Step {currentStepIndex + 1}</div>
              </div>
              <h2 className="text-xl font-black text-gray-900 leading-tight">{selectedGuide.steps[currentStepIndex].text}</h2>
              <div className="p-4 bg-green-50 rounded-2xl border border-green-100">
                <p className="text-xs font-medium text-green-800">{selectedGuide.steps[currentStepIndex].feedback}</p>
              </div>
              <div className="flex gap-4">
                <button onClick={() => speakGuide(selectedGuide, selectedGuide.steps[currentStepIndex])} className="flex-1 py-4 bg-blue-50 text-blue-600 rounded-2xl font-black text-[10px] uppercase tracking-widest">🔊 Listen</button>
                <button onClick={() => currentStepIndex < selectedGuide.steps.length - 1 ? setCurrentStepIndex(currentStepIndex+1) : setSelectedGuide(null)} className="flex-[2] py-4 bg-red-600 text-white rounded-2xl font-black shadow-lg">
                  {currentStepIndex < selectedGuide.steps.length - 1 ? 'NEXT STEP' : 'GUIDE FINISHED'}
                </button>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'checker' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-[40px] border-2 border-gray-50 shadow-sm space-y-4">
            <h3 className="text-xl font-black text-gray-800">Symptom Analysis</h3>
            <textarea value={symptomText} onChange={(e) => setSymptomText(e.target.value)} placeholder="Tell AI how you feel..." className="w-full h-32 p-5 bg-gray-50 rounded-3xl border-0 text-sm resize-none" />
            <button onClick={checkSymptoms} disabled={loading} className="w-full py-5 bg-red-600 text-white rounded-2xl font-black shadow-lg active:scale-95 transition-all">
              {loading ? 'ANALYZING...' : 'GET ADVICE'}
            </button>
          </div>
          {checkerResult && (
            <div className="bg-white p-8 rounded-[40px] shadow-xl animate-slideUp border border-gray-50">
              <div className="flex justify-between items-center mb-4">
                <span className="px-3 py-1 bg-red-50 text-red-600 text-[10px] font-black rounded-full uppercase">Severity: {checkerResult.severity}</span>
              </div>
              <p className="text-gray-600 text-sm font-medium mb-6">"{checkerResult.advice}"</p>
              <div className="space-y-3">
                {checkerResult.steps.map((s: string, i: number) => (
                  <div key={i} className="flex gap-3 text-xs text-gray-700 bg-gray-50 p-4 rounded-2xl font-bold">
                    <span className="text-red-600">{i+1}.</span>
                    <span>{s}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'messages' && (
        <div className="h-full flex flex-col animate-fadeIn">
          {!activeChatId ? (
            <div className="space-y-3">
              <h3 className="font-black text-xl mb-4 px-2">Conversations</h3>
              {dynamicDirectoryItems.map((user: any) => (
                <button key={user.id} onClick={() => setActiveChatId(user.id)} className="w-full flex items-center gap-4 p-5 bg-white rounded-[32px] border border-gray-50 shadow-sm active:scale-95 transition-all">
                  <div className="w-12 h-12 bg-red-100 rounded-2xl flex items-center justify-center text-xl overflow-hidden font-black">
                    {user.profilePicture ? <img src={user.profilePicture} className="w-full h-full object-cover" /> : (user.fullName || user.name).charAt(0)}
                  </div>
                  <div className="text-left">
                    <p className="font-black text-gray-800 text-sm">{user.fullName || user.name}</p>
                    <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">{user.type || user.role}</p>
                  </div>
                </button>
              ))}
            </div>
          ) : (
            <div className="flex flex-col h-[calc(100vh-220px)]">
              <div className="flex-1 overflow-y-auto space-y-4 pb-4">
                {relevantMessages.map(m => (
                  <div key={m.id} className={`max-w-[80%] p-4 rounded-3xl ${m.senderId === currentUser.id ? 'bg-red-600 text-white ml-auto rounded-tr-none' : 'bg-gray-100 text-gray-800 rounded-tl-none'}`}>
                    <p className="text-sm font-medium">{m.text}</p>
                  </div>
                ))}
              </div>
              <form onSubmit={(e) => { e.preventDefault(); const input = (e.currentTarget as any).msg; if(input.value) { handleSendMessage(input.value); input.value = ''; } }} className="flex gap-2">
                <input name="msg" placeholder="Type a message..." className="flex-1 p-4 bg-gray-50 rounded-2xl border-none outline-none text-sm" />
                <button type="submit" className="w-14 h-14 bg-red-600 text-white rounded-2xl flex items-center justify-center text-xl">↗️</button>
              </form>
            </div>
          )}
        </div>
      )}

      {activeTab === 'profile' && (
        <div className="space-y-6 animate-fadeIn">
          {!isEditingProfile ? (
            <>
              <div className="text-center p-10 bg-gray-50 rounded-[48px]">
                <div className="w-24 h-24 bg-red-600 text-white text-5xl font-black flex items-center justify-center rounded-full mx-auto mb-6 shadow-2xl border-4 border-white overflow-hidden">
                  {currentUser.profilePicture ? <img src={currentUser.profilePicture} className="w-full h-full object-cover" /> : currentUser.fullName.charAt(0)}
                </div>
                <h2 className="text-2xl font-black text-gray-800">{currentUser.fullName}</h2>
                <p className="text-red-600 text-[10px] font-black uppercase tracking-widest mt-2">{currentUser.role}</p>
                <button onClick={() => { setEditData(currentUser); setIsEditingProfile(true); }} className="mt-6 px-8 py-2.5 bg-white text-gray-800 rounded-full text-[10px] font-black uppercase shadow-sm border border-gray-100">EDIT PROFILE</button>
              </div>
              <div className="bg-white p-8 rounded-[40px] border-2 border-gray-50 space-y-6 shadow-sm">
                <InfoRow label="Phone" value={currentUser.phone} />
                <InfoRow label="Medical" value={`${currentUser.bloodGroup || 'N/A'} • ${currentUser.genotype || 'N/A'}`} />
                <InfoRow label="Emergency Network" value={`${currentUser.sosContacts.length} configured`} />
              </div>
              <button onClick={handleLogout} className="w-full py-5 bg-gray-100 text-gray-400 rounded-3xl font-black uppercase text-[10px] tracking-widest">Sign Out</button>
            </>
          ) : (
            <div className="space-y-6">
              <div className="text-center relative">
                <div onClick={() => fileInputRef.current?.click()} className="w-28 h-28 bg-gray-100 rounded-full mx-auto cursor-pointer border-4 border-white shadow-xl overflow-hidden flex items-center justify-center group">
                  {editData.profilePicture ? <img src={editData.profilePicture} className="w-full h-full object-cover" /> : <span className="text-4xl">📷</span>}
                </div>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
              </div>
              <div className="bg-white p-8 rounded-[40px] border-2 border-gray-100 space-y-5">
                <EditInput label="Name" value={editData.fullName} onChange={(val) => setEditData({...editData, fullName: val})} />
                <EditInput label="Phone" value={editData.phone} onChange={(val) => setEditData({...editData, phone: val})} />
                <EditInput label="Challenges" value={editData.healthChallenges} onChange={(val) => setEditData({...editData, healthChallenges: val})} placeholder="e.g. Asthma, Allergies" />
              </div>
              <div className="flex gap-4">
                <button onClick={() => setIsEditingProfile(false)} className="flex-1 py-5 bg-gray-100 text-gray-500 rounded-3xl font-black uppercase text-xs">Cancel</button>
                <button onClick={handleSaveProfile} className="flex-1 py-5 bg-red-600 text-white rounded-3xl font-black uppercase text-xs shadow-lg">Save</button>
              </div>
            </div>
          )}
        </div>
      )}
    </Layout>
  );
};

const QuickAction: React.FC<{ icon: string; label: string; bg: string; color: string; onClick: () => void }> = ({ icon, label, bg, color, onClick }) => (
  <button onClick={onClick} className={`${bg} p-8 rounded-[40px] flex flex-col items-center shadow-sm active:scale-95 transition-all`}>
    <span className="text-4xl mb-3">{icon}</span>
    <span className={`font-black uppercase text-[9px] tracking-widest ${color}`}>{label}</span>
  </button>
);

const InfoRow: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="flex flex-col">
    <span className="text-[8px] font-black text-gray-300 uppercase tracking-widest mb-1">{label}</span>
    <span className="text-sm font-bold text-gray-700">{value}</span>
  </div>
);

const EditInput: React.FC<{ label: string; value: string | undefined; onChange: (v: string) => void; placeholder?: string }> = ({ label, value, onChange, placeholder }) => (
  <div className="space-y-1">
    <label className="text-[8px] font-black text-red-600 uppercase tracking-widest ml-1">{label}</label>
    <input type="text" value={value || ''} onChange={(e) => onChange(e.target.value)} placeholder={placeholder} className="w-full p-4 bg-gray-50 rounded-2xl border-none outline-none text-sm font-medium" />
  </div>
);

const MedicalMetric: React.FC<{ icon: string; label: string; value: string }> = ({ icon, label, value }) => (
  <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm flex flex-col items-center text-center">
    <span className="text-2xl mb-1">{icon}</span>
    <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">{label}</span>
    <span className="text-sm font-black text-gray-800 mt-1">{value}</span>
  </div>
);

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, UserRole, Language, EmergencyGuide, InteractiveStep, HealthFacility, Message, EmergencyContact } from './types';
import { EMERGENCY_GUIDES, HEALTH_DIRECTORY, MOCK_BROADCASTS } from './constants';
import Layout from './components/Layout';
import SOSButton from './components/SOSButton';
import AuthScreen from './views/AuthScreen';
import { GeminiService } from './services/geminiService';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [activeTab, setActiveTab] = useState('home');
  const [selectedGuide, setSelectedGuide] = useState<EmergencyGuide | null>(null);
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [symptomText, setSymptomText] = useState('');
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [checkerResult, setCheckerResult] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  // Profile & Directory State
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [editData, setEditData] = useState<Partial<UserProfile>>({});
  const [directoryCategory, setDirectoryCategory] = useState('All');
  const [directorySearch, setDirectorySearch] = useState('');
  const [selectedPatientProfile, setSelectedPatientProfile] = useState<UserProfile | null>(null);

  // Messaging State
  const [messages, setMessages] = useState<Message[]>([]);
  const [activeChatId, setActiveChatId] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('user_profile');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.sosContacts) parsed.sosContacts = [];
      setCurrentUser(parsed);
    }
    const savedMsgs = localStorage.getItem('global_messages');
    if (savedMsgs) setMessages(JSON.parse(savedMsgs));
  }, []);

  const updateProfile = (updates: Partial<UserProfile>) => {
    if (!currentUser) return;
    const updated = { ...currentUser, ...updates };
    setCurrentUser(updated);
    localStorage.setItem('user_profile', JSON.stringify(updated));

    const allUsers = JSON.parse(localStorage.getItem('all_registered_users') || '[]');
    const index = allUsers.findIndex((u: UserProfile) => u.id === currentUser.id);
    if (index !== -1) {
      allUsers[index] = updated;
      localStorage.setItem('all_registered_users', JSON.stringify(allUsers));
    }
  };

  const handleSaveProfile = () => {
    updateProfile(editData);
    setIsEditingProfile(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setEditData(prev => ({ ...prev, profilePicture: base64 }));
      };
      reader.readAsDataURL(file);
    }
  };

  const dynamicDirectoryItems = useMemo(() => {
    const allRegistered = JSON.parse(localStorage.getItem('all_registered_users') || '[]');

    if (currentUser?.role === UserRole.PATIENT) {
      const helpers: HealthFacility[] = allRegistered
        .filter((u: UserProfile) => u.showInHelp && u.id !== currentUser?.id && (u.role === UserRole.ORGANIZATION || u.role === UserRole.CAREGIVER))
        .map((u: UserProfile) => ({
          id: u.id,
          name: u.role === UserRole.ORGANIZATION ? (u.organizationName || 'Unnamed Org') : u.fullName,
          type: u.role === UserRole.ORGANIZATION ? (u.firmType === 'Others' ? (u.otherFirmType as any || 'Organization') : u.firmType) : 'Volunteer',
          distance: 'Community Helper',
          phone: u.phone,
          address: u.address,
          profilePicture: u.profilePicture
        }));
      return [...HEALTH_DIRECTORY, ...helpers];
    } else {
      // For Responders: Show Patients
      return allRegistered.filter((u: UserProfile) => u.role === UserRole.PATIENT && u.showInHelp);
    }
  }, [currentUser]);

  const filteredDirectory = useMemo(() => {
    const items = dynamicDirectoryItems.filter(item => {
      const name = (item as any).fullName || (item as any).name || (item as any).organizationName || "";
      return name.toLowerCase().includes(directorySearch.toLowerCase());
    });

    if (currentUser?.role !== UserRole.PATIENT) return items;

    if (directoryCategory === 'All') return items;
    return items.filter((item: any) => {
      const type = item.type?.toLowerCase() || "";
      const cat = directoryCategory.toLowerCase();
      if (cat === 'volunteers') return type === 'volunteer' || type === 'caregiver' || type === 'provider';
      return type.includes(cat.slice(0, -1)) || type.includes(cat);
    });
  }, [dynamicDirectoryItems, directoryCategory, directorySearch, currentUser]);

  // Fix: Defined relevantMessages to filter conversations based on activeChatId
  const relevantMessages = useMemo(() => {
    if (!activeChatId || !currentUser) return [];
    return messages.filter(m => 
      (m.senderId === currentUser.id && m.receiverId === activeChatId) ||
      (m.senderId === activeChatId && m.receiverId === currentUser.id)
    );
  }, [messages, activeChatId, currentUser]);

  const handleSendMessage = (text: string) => {
    if (!currentUser || !activeChatId) return;
    const newMsg: Message = {
      id: Math.random().toString(36).substr(2, 9),
      senderId: currentUser.id,
      receiverId: activeChatId,
      text,
      timestamp: Date.now(),
    };
    const updatedMsgs = [...messages, newMsg];
    setMessages(updatedMsgs);
    localStorage.setItem('global_messages', JSON.stringify(updatedMsgs));
  };

  // Fix: Defined startChat to switch tabs and open a specific conversation
  const startChat = (id: string) => {
    setActiveChatId(id);
    setActiveTab('messages');
    setSelectedPatientProfile(null);
  };

  const speakGuide = async (guide: EmergencyGuide, step: InteractiveStep) => {
    try { await GeminiService.speakText(`${guide.title}. Step: ${step.text}`); } catch (e) {}
  };

  const checkSymptoms = async () => {
    if (!symptomText.trim()) return alert("Please describe symptoms.");
    setLoading(true);
    try {
      const result = await GeminiService.checkSymptoms(symptomText);
      setCheckerResult(result);
    } catch (e) { alert("Analysis failed."); } finally { setLoading(false); }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('user_profile');
    setActiveTab('home');
  };

  if (!currentUser) return <AuthScreen onLogin={setCurrentUser} />;

  return (
    <Layout 
      title={activeTab === 'guides' && selectedGuide ? selectedGuide.title : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} 
      activeTab={activeTab} 
      setActiveTab={(tab) => { 
        setActiveTab(tab); 
        setSelectedGuide(null); 
        setIsEditingProfile(false); 
        setSelectedPatientProfile(null);
        if(tab !== 'messages') setActiveChatId(null);
      }}
      onBack={selectedGuide ? () => setSelectedGuide(null) : activeChatId ? () => setActiveChatId(null) : isEditingProfile ? () => setIsEditingProfile(false) : selectedPatientProfile ? () => setSelectedPatientProfile(null) : undefined}
    >
      {activeTab === 'home' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-black text-gray-800">Hi, {currentUser.fullName.split(' ')[0]}</h2>
              <p className="text-gray-400 text-sm font-medium">Safe & Smart Help</p>
            </div>
            <button onClick={() => setActiveTab('profile')} className="w-14 h-14 bg-red-600 rounded-full flex items-center justify-center text-white text-xl font-black shadow-lg overflow-hidden border-2 border-white">
              {currentUser.profilePicture ? <img src={currentUser.profilePicture} className="w-full h-full object-cover" /> : currentUser.fullName.charAt(0)}
            </button>
          </div>
          <SOSButton user={currentUser} onUpdateContacts={(contacts) => updateProfile({ sosContacts: contacts })} />
          <div className="grid grid-cols-2 gap-4">
            <QuickAction icon="🩹" label="First Aid" bg="bg-blue-50" color="text-blue-900" onClick={() => setActiveTab('guides')} />
            <QuickAction icon="🩺" label="AI Symptoms" bg="bg-purple-50" color="text-purple-900" onClick={() => setActiveTab('checker')} />
          </div>
          <section className="bg-white p-6 rounded-[32px] border-2 border-gray-50">
            <h3 className="font-black text-sm uppercase tracking-widest text-gray-400 mb-4">Latest Alerts</h3>
            {MOCK_BROADCASTS.map(alert => (
              <div key={alert.id} className="p-4 bg-orange-50 rounded-2xl border border-orange-100 mb-2 last:mb-0">
                <p className="font-bold text-gray-800 text-xs">{alert.title}</p>
                <p className="text-[10px] text-gray-500 mt-1">{alert.content}</p>
              </div>
            ))}
          </section>
        </div>
      )}

      {activeTab === 'directory' && (
        <div className="space-y-4 animate-fadeIn">
          <div className="relative">
            <input 
              type="text" 
              placeholder={currentUser.role === UserRole.PATIENT ? "Search Health Facilities..." : "Search Community Patients..."}
              value={directorySearch}
              onChange={(e) => setDirectorySearch(e.target.value)}
              className="w-full p-4 bg-gray-50 rounded-2xl border-none text-sm font-medium focus:ring-2 focus:ring-red-100 outline-none"
            />
            <span className="absolute right-4 top-4 opacity-30">🔍</span>
          </div>

          {currentUser.role === UserRole.PATIENT && (
            <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide px-1">
              {['All', 'Clinic', 'Hospital', 'Pharmacy', 'Volunteers'].map(cat => (
                <button 
                  key={cat} 
                  onClick={() => setDirectoryCategory(cat)}
                  className={`px-6 py-2 rounded-full text-[10px] font-black transition-all border ${directoryCategory === cat ? 'bg-red-600 text-white border-red-700' : 'bg-white text-gray-400 border-gray-100'}`}
                >
                  {cat}
                </button>
              ))}
            </div>
          )}

          <div className="space-y-3">
            {selectedPatientProfile ? (
              <div className="animate-slideUp space-y-6">
                <div className="bg-red-50 p-6 rounded-[32px] border border-red-100 flex flex-col items-center">
                  <div className="w-24 h-24 bg-red-600 rounded-full mb-4 flex items-center justify-center text-white text-4xl font-black overflow-hidden border-4 border-white shadow-xl">
                    {selectedPatientProfile.profilePicture ? <img src={selectedPatientProfile.profilePicture} className="w-full h-full object-cover" /> : selectedPatientProfile.fullName.charAt(0)}
                  </div>
                  <h3 className="text-xl font-black text-red-900">{selectedPatientProfile.fullName}</h3>
                  <p className="text-[10px] font-black text-red-600 uppercase tracking-[2px]">{selectedPatientProfile.gender} • Age {selectedPatientProfile.age}</p>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <MedicalMetric icon="🩸" label="Blood Group" value={selectedPatientProfile.bloodGroup || 'Not set'} />
                  <MedicalMetric icon="🧬" label="Genotype" value={selectedPatientProfile.genotype || 'Not set'} />
                </div>

                <div className="bg-white p-6 rounded-[32px] border border-gray-100 shadow-sm space-y-4">
                  <div>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Health Challenges</p>
                    <p className="text-sm font-medium text-gray-700">{selectedPatientProfile.healthChallenges || 'None reported'}</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Address</p>
                    <p className="text-sm font-medium text-gray-700">{selectedPatientProfile.address}</p>
                  </div>
                </div>

                <div className="flex gap-4">
                  <button onClick={() => window.open(`tel:${selectedPatientProfile.phone}`)} className="flex-1 py-5 bg-red-600 text-white rounded-2xl font-black shadow-lg">CALL NOW</button>
                  <button onClick={() => startChat(selectedPatientProfile.id)} className="flex-1 py-5 bg-blue-600 text-white rounded-2xl font-black shadow-lg">MESSAGE</button>
                </div>
              </div>
            ) : filteredDirectory.map((item: any, i) => (
              <div key={i} className="bg-white p-5 rounded-[32px] border border-gray-50 shadow-sm flex items-center gap-4 active:scale-[0.98] transition-all" onClick={() => currentUser.role !== UserRole.PATIENT ? setSelectedPatientProfile(item) : null}>
                <div className="w-14 h-14 bg-red-50 text-red-600 rounded-2xl flex items-center justify-center text-2xl overflow-hidden font-black">
                  {item.profilePicture ? <img src={item.profilePicture} className="w-full h-full object-cover" /> : (item.role === UserRole.PATIENT ? item.fullName.charAt(0) : '🏥')}
                </div>
                <div className="flex-1">
                  <h4 className="font-black text-gray-800 text-sm">{item.fullName || item.name || item.organizationName}</h4>
                  <p className="text-[9px] font-bold text-red-600 uppercase tracking-widest">{item.type || (item.role === UserRole.PATIENT ? `Patient • ${item.bloodGroup}` : 'Responder')}</p>
                </div>
                {currentUser.role === UserRole.PATIENT && (
                  <button onClick={(e) => { e.stopPropagation(); startChat(item.id); }} className="p-3 bg-blue-50 text-blue-600 rounded-xl text-xs">💬</button>
                )}
              </div>
            ))}
            {filteredDirectory.length === 0 && (
              <div className="text-center py-20 opacity-30 font-black italic">No records found</div>
            )}
          </div>
        </div>
      )}

      {activeTab === 'guides' && (
        <div className="animate-fadeIn">
          {!selectedGuide ? (
            <div className="grid grid-cols-2 gap-4">
              {EMERGENCY_GUIDES.map(guide => (
                <button key={guide.id} onClick={() => { setSelectedGuide(guide); setCurrentStepIndex(0); speakGuide(guide, guide.steps[0]); }} className="bg-white p-6 rounded-[32px] border-2 border-gray-50 shadow-sm flex flex-col items-center active:scale-95 transition-all">
                  <span className="text-4xl mb-3">{guide.icon}</span>
                  <span className="font-bold text-gray-800 text-[10px] text-center uppercase tracking-widest">{guide.title}</span>
                </button>
              ))}
            </div>
          ) : (
            <div className="space-y-6">
              <div className="relative overflow-hidden rounded-[32px] shadow-xl">
                <img src={selectedGuide.image} className="w-full h-52 object-cover" />
                <div className="absolute bottom-4 left-4 bg-red-600 text-white px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest">Step {currentStepIndex + 1}</div>
              </div>
              <h2 className="text-xl font-black text-gray-900 leading-tight">{selectedGuide.steps[currentStepIndex].text}</h2>
              <div className="p-4 bg-green-50 rounded-2xl border border-green-100">
                <p className="text-xs font-medium text-green-800">{selectedGuide.steps[currentStepIndex].feedback}</p>
              </div>
              <div className="flex gap-4">
                <button onClick={() => speakGuide(selectedGuide, selectedGuide.steps[currentStepIndex])} className="flex-1 py-4 bg-blue-50 text-blue-600 rounded-2xl font-black text-[10px] uppercase tracking-widest">🔊 Listen</button>
                <button onClick={() => currentStepIndex < selectedGuide.steps.length - 1 ? setCurrentStepIndex(currentStepIndex+1) : setSelectedGuide(null)} className="flex-[2] py-4 bg-red-600 text-white rounded-2xl font-black shadow-lg">
                  {currentStepIndex < selectedGuide.steps.length - 1 ? 'NEXT STEP' : 'GUIDE FINISHED'}
                </button>
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'checker' && (
        <div className="space-y-6 animate-fadeIn">
          <div className="bg-white p-8 rounded-[40px] border-2 border-gray-50 shadow-sm space-y-4">
            <h3 className="text-xl font-black text-gray-800">Symptom Analysis</h3>
            <textarea value={symptomText} onChange={(e) => setSymptomText(e.target.value)} placeholder="Tell AI how you feel..." className="w-full h-32 p-5 bg-gray-50 rounded-3xl border-0 text-sm resize-none" />
            <button onClick={checkSymptoms} disabled={loading} className="w-full py-5 bg-red-600 text-white rounded-2xl font-black shadow-lg active:scale-95 transition-all">
              {loading ? 'ANALYZING...' : 'GET ADVICE'}
            </button>
          </div>
          {checkerResult && (
            <div className="bg-white p-8 rounded-[40px] shadow-xl animate-slideUp border border-gray-50">
              <div className="flex justify-between items-center mb-4">
                <span className="px-3 py-1 bg-red-50 text-red-600 text-[10px] font-black rounded-full uppercase">Severity: {checkerResult.severity}</span>
              </div>
              <p className="text-gray-600 text-sm font-medium mb-6">"{checkerResult.advice}"</p>
              <div className="space-y-3">
                {checkerResult.steps.map((s: string, i: number) => (
                  <div key={i} className="flex gap-3 text-xs text-gray-700 bg-gray-50 p-4 rounded-2xl font-bold">
                    <span className="text-red-600">{i+1}.</span>
                    <span>{s}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {activeTab === 'messages' && (
        <div className="h-full flex flex-col animate-fadeIn">
          {!activeChatId ? (
            <div className="space-y-3">
              <h3 className="font-black text-xl mb-4 px-2">Conversations</h3>
              {dynamicDirectoryItems.map((user: any) => (
                <button key={user.id} onClick={() => setActiveChatId(user.id)} className="w-full flex items-center gap-4 p-5 bg-white rounded-[32px] border border-gray-50 shadow-sm active:scale-95 transition-all">
                  <div className="w-12 h-12 bg-red-100 rounded-2xl flex items-center justify-center text-xl overflow-hidden font-black">
                    {user.profilePicture ? <img src={user.profilePicture} className="w-full h-full object-cover" /> : (user.fullName || user.name).charAt(0)}
                  </div>
                  <div className="text-left">
                    <p className="font-black text-gray-800 text-sm">{user.fullName || user.name}</p>
                    <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">{user.type || user.role}</p>
                  </div>
                </button>
              ))}
            </div>
          ) : (
            <div className="flex flex-col h-[calc(100vh-220px)]">
              <div className="flex-1 overflow-y-auto space-y-4 pb-4">
                {relevantMessages.map(m => (
                  <div key={m.id} className={`max-w-[80%] p-4 rounded-3xl ${m.senderId === currentUser.id ? 'bg-red-600 text-white ml-auto rounded-tr-none' : 'bg-gray-100 text-gray-800 rounded-tl-none'}`}>
                    <p className="text-sm font-medium">{m.text}</p>
                  </div>
                ))}
              </div>
              <form onSubmit={(e) => { e.preventDefault(); const input = (e.currentTarget as any).msg; if(input.value) { handleSendMessage(input.value); input.value = ''; } }} className="flex gap-2">
                <input name="msg" placeholder="Type a message..." className="flex-1 p-4 bg-gray-50 rounded-2xl border-none outline-none text-sm" />
                <button type="submit" className="w-14 h-14 bg-red-600 text-white rounded-2xl flex items-center justify-center text-xl">↗️</button>
              </form>
            </div>
          )}
        </div>
      )}

      {activeTab === 'profile' && (
        <div className="space-y-6 animate-fadeIn">
          {!isEditingProfile ? (
            <>
              <div className="text-center p-10 bg-gray-50 rounded-[48px]">
                <div className="w-24 h-24 bg-red-600 text-white text-5xl font-black flex items-center justify-center rounded-full mx-auto mb-6 shadow-2xl border-4 border-white overflow-hidden">
                  {currentUser.profilePicture ? <img src={currentUser.profilePicture} className="w-full h-full object-cover" /> : currentUser.fullName.charAt(0)}
                </div>
                <h2 className="text-2xl font-black text-gray-800">{currentUser.fullName}</h2>
                <p className="text-red-600 text-[10px] font-black uppercase tracking-widest mt-2">{currentUser.role}</p>
                <button onClick={() => { setEditData(currentUser); setIsEditingProfile(true); }} className="mt-6 px-8 py-2.5 bg-white text-gray-800 rounded-full text-[10px] font-black uppercase shadow-sm border border-gray-100">EDIT PROFILE</button>
              </div>
              <div className="bg-white p-8 rounded-[40px] border-2 border-gray-50 space-y-6 shadow-sm">
                <InfoRow label="Phone" value={currentUser.phone} />
                <InfoRow label="Medical" value={`${currentUser.bloodGroup || 'N/A'} • ${currentUser.genotype || 'N/A'}`} />
                <InfoRow label="Emergency Network" value={`${currentUser.sosContacts.length} configured`} />
              </div>
              <button onClick={handleLogout} className="w-full py-5 bg-gray-100 text-gray-400 rounded-3xl font-black uppercase text-[10px] tracking-widest">Sign Out</button>
            </>
          ) : (
            <div className="space-y-6">
              <div className="text-center relative">
                <div onClick={() => fileInputRef.current?.click()} className="w-28 h-28 bg-gray-100 rounded-full mx-auto cursor-pointer border-4 border-white shadow-xl overflow-hidden flex items-center justify-center group">
                  {editData.profilePicture ? <img src={editData.profilePicture} className="w-full h-full object-cover" /> : <span className="text-4xl">📷</span>}
                </div>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
              </div>
              <div className="bg-white p-8 rounded-[40px] border-2 border-gray-100 space-y-5">
                <EditInput label="Name" value={editData.fullName} onChange={(val) => setEditData({...editData, fullName: val})} />
                <EditInput label="Phone" value={editData.phone} onChange={(val) => setEditData({...editData, phone: val})} />
                <EditInput label="Challenges" value={editData.healthChallenges} onChange={(val) => setEditData({...editData, healthChallenges: val})} placeholder="e.g. Asthma, Allergies" />
              </div>
              <div className="flex gap-4">
                <button onClick={() => setIsEditingProfile(false)} className="flex-1 py-5 bg-gray-100 text-gray-500 rounded-3xl font-black uppercase text-xs">Cancel</button>
                <button onClick={handleSaveProfile} className="flex-1 py-5 bg-red-600 text-white rounded-3xl font-black uppercase text-xs shadow-lg">Save</button>
              </div>
            </div>
          )}
        </div>
      )}
    </Layout>
  );
};

const QuickAction: React.FC<{ icon: string; label: string; bg: string; color: string; onClick: () => void }> = ({ icon, label, bg, color, onClick }) => (
  <button onClick={onClick} className={`${bg} p-8 rounded-[40px] flex flex-col items-center shadow-sm active:scale-95 transition-all`}>
    <span className="text-4xl mb-3">{icon}</span>
    <span className={`font-black uppercase text-[9px] tracking-widest ${color}`}>{label}</span>
  </button>
);

const InfoRow: React.FC<{ label: string; value: string }> = ({ label, value }) => (
  <div className="flex flex-col">
